INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('26-clinic-os',3,26,'CLINIC OS','He dieu hanh phong kham',26,'draft','2026-06-20T16:07:51Z','2026-06-20T16:07:51Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d','26-clinic-os',NULL,2,'26.1 Định Nghĩa Và Vị Trí Chiến Lược','261-inh-nghia-va-vi-tri-chien-luoc',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('695671af-411f-448a-9573-59edbf982873','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',0,'text','**Clinic OS = Hệ thống vận hành lâm sàng + Trải nghiệm bệnh nhân + Kiểm soát chất lượng + Phối hợp nội bộ.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7252bf8a-dd6d-4880-80e8-9f7807fa0673','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',1,'text','Nó bao gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1178f6c3-18d4-416c-92c0-fabda49bcf68','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',2,'text','- Quy trình tiếp nhận bệnh nhân- Quy trình khám và chẩn đoán- Quy trình tư vấn điều trị- Quy trình điều phối ghế, bác sĩ, phụ tá- Quy trình kiểm soát chất lượng điều trị- Quy trình chăm sóc sau điều trị- Quy trình ghi nhận case, hình ảnh, review- Quy trình xử lý khiếu nại- Quy trình đào tạo nội bộ',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1d8ffd0-f3b6-42ef-9fd7-677de15b37b7','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',3,'text','**Nơi Biến Lời Hứa Thương Hiệu Thành Trải Nghiệm Thực Tế**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e9d87ad-f103-4640-88df-334c5dfd5069','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',4,'text','Nếu **Marketing OS** tạo nhu cầu, **Sales OS** chuyển đổi khách hàng, thì **Clinic OS** đảm bảo phòng khám có đủ năng lực tiếp nhận, thăm khám, điều trị, chăm sóc và tạo trải nghiệm khiến bệnh nhân tin tưởng, quay lại và giới thiệu. Đây là phân hệ trực tiếp quản trị toàn bộ hoạt động vật lý thực sàn tại phòng khám RHM: Từ năng lực tiếp đón, quy trình chẩn đoán lâm sàng, tiêu chuẩn hóa thủ thuật điều trị, kiểm soát nhiễm khuẩn khép kín, cho đến việc thiết kế hành trình trải nghiệm khách hàng (Customer Experience).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c961b27-cf9b-4a0a-9f95-0e2f41df4c0a','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',5,'text','Nhiều chủ phòng khám nha khoa hiện nay thường mắc sai lầm lớn khi chỉ tập trung đổ tiền vào quảng cáo ở đầu phễu nhưng lại để sảnh nha vận hành một cách hỗn loạn, bản năng và phụ thuộc hoàn toàn vào tâm trạng của nhân sự. Cách làm chắp vá này trực tiếp tạo ra sự đứt gãy lòng tin của bệnh nhân ngay tại điểm chạm thực tế đầu tiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49543b58-719d-42e8-8aef-738edfae3b94','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',6,'text','**Tuyên ngôn tối cao của Clinic OS:***"Marketing và Sales chỉ giúp phòng khám trao đi một lời hứa thương hiệu trên không gian mạng. Nhưng chính Clinic OS mới là nơi thực hiện lời hứa đó một cách trọn vẹn và y đức nhất ngay tại ghế điều trị."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ce94308-53c6-4751-b8e9-d5beeac9e47d','7658ccc1-5e3c-4f8d-bbb8-8514a8c5fc4d',7,'text','Khi **Clinic OS** đạt độ chín vận hành, nó sẽ triệt tiêu hoàn toàn sự biến thiên về mặt chất lượng dịch vụ do yếu tố con người, đảm bảo mỗi bệnh nhân khi bước chân vào phòng khám đều nhận được một tiêu chuẩn chăm sóc tử tế và chuyên nghiệp y hệt nhau, bất kể ca điều trị đó do bác sĩ hay phụ tá nào trực làm việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f53d9b93-39de-4513-a6b5-c46fdace58f1','26-clinic-os',NULL,2,'26.2 Năm Vai Trò Cốt Lõi Giải Mã Bài Toán Thực Sàn Của Clinic OS','262-nam-vai-tro-cot-loi-giai-ma-bai-toan-thuc-san-cua-clinic-os',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f09ebca3-d6d1-4089-a6e9-9a0ef4eea1a6','f53d9b93-39de-4513-a6b5-c46fdace58f1',8,'text','Hệ điều hành vận hành lâm sàng được kiến tạo để giúp Ban điều hành trả lời một cách định lượng và chuẩn hóa 5 câu hỏi sinh tử trong quản trị thực tế:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12ed3911-6bcb-496e-98bb-950ce5002358','f53d9b93-39de-4513-a6b5-c46fdace58f1',9,'text','- Bệnh nhân sau khi đặt lịch được tiếp nhận như thế nào?- Quy trình khám, tư vấn, điều trị có đồng nhất không?- Trải nghiệm tại phòng khám có đủ tốt để tạo niềm tin không?- Đội ngũ bác sĩ, phụ tá, lễ tân, điều phối vận hành theo chuẩn nào?- Làm sao để mỗi ca điều trị trở thành tài sản tăng trưởng mới: case, review, referral, retention?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a6124a94-f7f6-45e0-9395-64eb8cdb5ca1','26-clinic-os',NULL,2,'26.3 Mục tiêu của Clinic OS','263-muc-tieu-cua-clinic-os',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f6e073a-41ad-490a-823e-1e6b1389e5dc','a6124a94-f7f6-45e0-9395-64eb8cdb5ca1',10,'text','Clinic OS không chỉ nhằm “khám và điều trị”, mà nhằm tạo ra một hệ thống phòng khám có thể vận hành ổn định, đồng nhất và mở rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5024b4a9-18bb-40bc-a402-0f84a59ab0b1','a6124a94-f7f6-45e0-9395-64eb8cdb5ca1',11,'text','- Tăng tỷ lệ bệnh nhân đến khám đúng lịch.- Tăng tỷ lệ bệnh nhân đồng ý điều trị sau khi khám.- Tăng chất lượng trải nghiệm tại phòng khám.- Giảm lỗi vận hành, trễ lịch, thiếu vật tư, thiếu hồ sơ.- Tăng review tốt sau điều trị.- Tăng khả năng bệnh nhân quay lại và giới thiệu.- Chuẩn hóa quy trình để có thể đào tạo nhân sự mới nhanh hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3dde6227-353a-42ea-a47d-53c032d653b7','26-clinic-os',NULL,2,'26.4 Clinic OS gồm 7 module chính','264-clinic-os-gom-7-module-chinh',3,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bb4386da-b48d-4bd4-89ed-d3324af13d10','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 1: RECEPTION OS - HỆ THỐNG TIẾP NHẬN MẶT TIỀN VÀ ĐIỀU PHỐI ĐIỂM CHẠM VẬT LÝ ĐẦU TIÊN','module-1-reception-os-he-thong-tiep-nhan-mat-tien-va-ieu-phoi-iem-cham-vat-ly-au',4,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d211f8c9-69d9-48ab-bff5-78817dc4871e','26-clinic-os','bb4386da-b48d-4bd4-89ed-d3324af13d10',4,'Tư Duy Cốt Lõi: Đánh Chặn Định Kiến, Số Hóa Điểm Chạm Vật Lý Đầu Tiên','tu-duy-cot-loi-anh-chan-inh-kien-so-hoa-iem-cham-vat-ly-au-tien',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('290f44d0-f99b-407b-a453-c2f9d8affdcd','d211f8c9-69d9-48ab-bff5-78817dc4871e',12,'text','Nếu như *Marketing OS* và *Sales OS* vận hành xuất sắc trên không gian mạng để tạo ra một lời hứa thương hiệu hoàn hảo, thì **Reception OS (Hệ thống tiếp nhận bệnh nhân)** chính là bộ lọc vật lý đầu tiên kiểm chứng lời hứa đó khi bệnh nhân bước chân qua cửa phòng khám của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9c77592-9f7b-43aa-8275-5e6620cb8f25','d211f8c9-69d9-48ab-bff5-78817dc4871e',13,'text','Bản chất tâm lý của bệnh nhân khi đến nha khoa là sự tổng hòa của hai trạng thái tiêu cực: Nỗi sợ đau và sự phòng thủ hoài nghi về mặt tài chính. Nếu quầy lễ tân vận hành một cách rời rạc, để bệnh nhân đứng bơ vơ quá 10 giây không có người chào đón, hoặc bắt họ phải ngồi khai báo lại từ đầu những thông tin đã chat trực tuyến, toàn bộ pháo đài lòng tin tích lũy trước đó sẽ sụp đổ ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd5e4820-4805-4516-95a8-fcd9dc1add55','d211f8c9-69d9-48ab-bff5-78817dc4871e',14,'text','Trong kiến trúc **Dental Empire OS**, quầy Lễ tân không phải là nơi làm thủ tục hành chính đơn thuần. Đây là **Trạm sưởi ấm cảm xúc và Khơi thông đường ống trải nghiệm**. *Reception OS* ra đời để thiết lập một tiêu chuẩn tiếp đón không ma sát, biến 5 phút đầu tiên tại sảnh chờ thành mỏ neo Peak Wow (Đỉnh cao cảm xúc), khiến bệnh nhân lập tức cảm nhận được sự chuyên nghiệp, y đức tử tế và hoàn toàn an tâm giao phó nụ cười của mình cho đội ngũ Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc570b95-bcfe-404d-af16-7a7a81eb91fa','26-clinic-os','bb4386da-b48d-4bd4-89ed-d3324af13d10',4,'Sáu Nhiệm Vụ Sinh Tử Của Nhân Sự Tuyến Đầu','sau-nhiem-vu-sinh-tu-cua-nhan-su-tuyen-au',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3eedee33-0a2a-485b-b9ba-b81b636f93ab','dc570b95-bcfe-404d-af16-7a7a81eb91fa',15,'text','Để bảo toàn năng lượng và triệt tiêu mọi sự lãng phí thời gian của bệnh nhân, phân hệ Reception OS buộc nhân sự trực sàn phải thực thi trọn vẹn 6 nhiệm vụ kỹ thuật:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('788a259f-74fa-4976-9e06-ec2162c73ab2','dc570b95-bcfe-404d-af16-7a7a81eb91fa',16,'text','- **Nhận diện và Định danh tức thì:** Chủ động nhận diện, check-in mã lịch hẹn và chào bệnh nhân bằng tên riêng trong thời gian vàng 10 giây đầu tiên.- **Đối soát Payload dữ liệu (Sales-to-Clinic):** Đối chiếu chính xác thông tin cá nhân, dịch vụ quan tâm mũi nhọn (Implant, Chỉnh nha) để khớp dữ liệu trực tuyến.- **Kiểm soát và Điều phối công suất sàn:** Nắm chắc sơ đồ ghế nha trống và lịch trực thực tế của khối Bác sĩ/Phụ tá để điều phối nhịp nhàng, triệt tiêu thời gian chờ chết.- **Cập nhật trạng thái số hóa:** Chuyển đổi trạng thái hồ sơ trên CRM từ `Booked` sang `Arrived` theo thời gian thực (Real-time update).- **Giải tỏa rào cản thông tin:** Hướng dẫn rõ ràng lộ trình thăm khám, chụp phim chẩn đoán hình ảnh tại chỗ để khách hàng làm chủ tiến trình trải nghiệm.- **Bàn giao ấm (Warm Handoff):** Chuyển giao trọn vẹn hồ sơ tâm lý và điểm đau y khoa của khách sang cho bộ phận điều phối lâm sàng hoặc trợ thủ trực ca.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('481d3f72-98da-48d6-b1d7-2c6cd967b6b3','26-clinic-os','bb4386da-b48d-4bd4-89ed-d3324af13d10',4,'Quy Trình Tuyến Tính 6 Bước Đón Tiếp Không Ma Sát','quy-trinh-tuyen-tinh-6-buoc-on-tiep-khong-ma-sat',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96710a2c-595b-4bc8-bf8e-67d7c323a43d','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',17,'text','Mọi bệnh nhân khi bước qua cửa cơ sở nha khoa tại Hà Nội bắt buộc phải được dẫn dắt dịch chuyển tuần tự theo đúng đường ống 6 bước chuẩn hóa dưới đây. Nhân sự tuyệt đối không được cắt xén quy trình hoặc làm đảo lộn thứ tự các điểm chạm cảm xúc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f659d2c4-f3fd-40c2-9d4f-09ddf58ebe7b','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Đón tiếp Peak Wow và Chào mở cửa:','on-tiep-peak-wow-va-chao-mo-cua',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac1ee40d-aea1-4418-be7b-043c22c29269','f659d2c4-f3fd-40c2-9d4f-09ddf58ebe7b',18,'text','*10 giây đầu tiên.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c7e686b-1008-48b5-8baa-f17d400098f7','f659d2c4-f3fd-40c2-9d4f-09ddf58ebe7b',19,'text','Nhân sự Lễ tân chủ động đẩy cửa đón khách, mỉm cười chuẩn góc 15 độ, chào bệnh nhân bằng tên riêng (nếu dựa vào giờ lịch hẹn đối soát trước). Đón túi xách, áo khoác và hướng dẫn khách thay dép chuyên dụng của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6568f89e-e30e-4585-bd84-ee0e07e0265c','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Đối soát dữ liệu và Khớp Payload:','oi-soat-du-lieu-va-khop-payload',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c057dc8e-cfe9-469f-985d-14094f3bc2ca','6568f89e-e30e-4585-bd84-ee0e07e0265c',20,'text','*Thời gian dưới 60 giây.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3bc4d23f-0250-4757-8557-060277e07ab4','6568f89e-e30e-4585-bd84-ee0e07e0265c',21,'text','Mời khách ngồi tại quầy tiếp đón. Xin phép xác nhận lại 3 thông tin cốt lõi: Họ tên, Số điện thoại định danh, và Dịch vụ quan tâm chính để đối chiếu với thông tin bộ phận Online đã bàn giao trên CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc525d9f-86db-4077-9347-ff78b808a1df','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Kiểm toán mã lịch hẹn hệ thống:','kiem-toan-ma-lich-hen-he-thong',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b65b00e-1b6c-4be4-bab6-c91c7ea34ae6','dc525d9f-86db-4077-9347-ff78b808a1df',22,'text','*Thời gian dưới 30 giây.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3213ff77-431f-419f-8b31-e890d3471f97','dc525d9f-86db-4077-9347-ff78b808a1df',23,'text','Truy xuất mã hẹn cố định trên phần mềm, kiểm tra chính xác khung giờ ghế nha đã khóa và tên Bác sĩ chủ trì phác đồ điều trị được chỉ định riêng cho ca lâm sàng này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f557e778-ef27-45f6-b8af-4316bfa2c571','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Đột biến trạng thái cơ sở dữ liệu:','ot-bien-trang-thai-co-so-du-lieu',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48cad26e-e802-4188-9381-929e5bb4c60d','f557e778-ef27-45f6-b8af-4316bfa2c571',24,'text','*Thực hiện tức thì trên CRM.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb41b1b5-f0fd-4024-9349-665c42a51b95','f557e778-ef27-45f6-b8af-4316bfa2c571',25,'text','Bấm nút chuyển đổi trạng thái hồ sơ khách hàng sang mục `Arrived` (Đã đến khám). Lúc này, hệ thống sẽ tự động bắn thông báo đẩy (Push Notification) đến máy tính của Bác sĩ trực phòng VIP và Phụ tá ca để chuẩn bị phòng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9c551d3b-a238-4752-a490-6570811a70d7','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Briefing lộ trình khám và Hướng dẫn sảnh chờ:','briefing-lo-trinh-kham-va-huong-dan-sanh-cho',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('279fbaff-e089-42d1-86c0-781f2f2e6604','9c551d3b-a238-4752-a490-6570811a70d7',26,'text','*Thời gian dưới 2 phút.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2841795-a0e4-4c9d-9328-e082bd2c67fe','9c551d3b-a238-4752-a490-6570811a70d7',27,'text','Mời khách di chuyển sang sảnh chờ VIP. Phục vụ nước uống, thông báo rõ ràng thời gian chờ dự kiến (SLA luôn luôn dưới 5 phút) và giải thích trước: *"Lát nữa mình sẽ được phụ tá dẫn đi chụp phim CT Cone Beam tầm soát trước, sau đó Bác sĩ Vinh sẽ phân tích phim trực tiếp cho mình ạ"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('96a448c9-1aa8-4984-a9bc-66d60d75f26b','26-clinic-os','481d3f72-98da-48d6-b1d7-2c6cd967b6b3',5,'Bàn giao ấm (Warm Handoff Payload):','ban-giao-am-warm-handoff-payload',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a60f2366-699f-473b-b350-7dafdcfecbff','96a448c9-1aa8-4984-a9bc-66d60d75f26b',28,'text','*Khi Bác sĩ/Phụ tá ra đón.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('733a5424-5b40-4951-ad00-0230a4c8b23b','96a448c9-1aa8-4984-a9bc-66d60d75f26b',29,'text','Khi Phụ tá ra sảnh đón khách vào phòng máy, Lễ tân thực hiện bàn giao hồ sơ cứng kèm lời dặn dặn dò nội bộ: *"Đây là anh A, đến khám Implant răng cấm, nguồn TikTok, anh ấy khá sợ đau buốt sinh học, Bác sĩ Vinh lưu ý giải thích kỹ công nghệ giảm đau giúp em nhé"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1dbb7b19-d588-489c-b787-1dd857c557b9','26-clinic-os','bb4386da-b48d-4bd4-89ed-d3324af13d10',4,'Bảng đánh giá Hiệu Suất Reception OS (Standardized SLA Checklist)','bang-anh-gia-hieu-suat-reception-os-standardized-sla-checklist',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('adae58e4-650d-426c-abf5-dd601ec5037a','1dbb7b19-d588-489c-b787-1dd857c557b9',30,'text','Để nhà quản trị hoặc Tư vấn trưởng có thể tiến hành kiểm tra ngẫu nhiên (Audit) chất lượng vận hành của quầy Lễ tân hằng tuần, toàn bộ hành vi phải được đối soát theo bảng tiêu chuẩn định lượng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8aec89cf-1c4c-45f7-9297-cc19d0e44f00','1dbb7b19-d588-489c-b787-1dd857c557b9',31,'image',NULL,'book/26-clinic-os/b84f7d0f-0d90-4f51-9020-0d360e113057-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a10d117-aa76-4d0a-903a-8ba9c82fd499','26-clinic-os','bb4386da-b48d-4bd4-89ed-d3324af13d10',4,'Mỏ Neo Toán Học: Chỉ Số Ma Sát Tiền Sàn (Intake Friction Index)','mo-neo-toan-hoc-chi-so-ma-sat-tien-san-intake-friction-index',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f2c6017-0652-4efa-8ce9-11249950d3ef','9a10d117-aa76-4d0a-903a-8ba9c82fd499',32,'image',NULL,'book/26-clinic-os/c5d7be59-9556-43d6-b429-335311777a24-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81f866ba-9807-470a-8e99-fd3e007a2d90','9a10d117-aa76-4d0a-903a-8ba9c82fd499',33,'text','Hệ điều hành kiểm soát năng lực hành vi và chất lượng điểm chạm của quầy Lễ tân thông qua công thức toán học đo lường **Chỉ số Ma sát Tiếp nhận (Intake Friction Index - IFI)** hằng tháng trích xuất từ dữ liệu thời gian thực:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f4743d2-b8f6-49e7-b4b1-f3f5df3a34ae','9a10d117-aa76-4d0a-903a-8ba9c82fd499',34,'text','IFI = \\frac{\\text{Tổng số phút bệnh nhân phải ngồi chờ thực tế từ lúc Check-in đến khi lên ghế nha}}{\\text{Tổng thời gian hẹn tiêu chuẩn định mức quy định (5 phút)}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('080d6257-3ac1-4a9f-abee-f8fc35d052d5','9a10d117-aa76-4d0a-903a-8ba9c82fd499',35,'text','- **Ngưỡng mục tiêu quản trị:** Chỉ số IFI lý tưởng nhất phải đạt mốc \\le 1.0 (Tức là thời gian chờ thực tế nhỏ hơn hoặc bằng 5 phút định mức).- **Cảnh báo lỗi sàn:** Nếu IFI > 2.0 (Khách phải ngồi chờ đợi vô định trên 10 phút), bộ máy đang gặp lỗi nghẽn mạch điều phối lịch hẹn của *Sales OS* hoặc năng suất dọn phòng điều trị của *Clinic OS* quá chậm. Ban giám đốc bắt buộc phải can thiệp để tinh chỉnh lại công suất sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('171470c5-acbb-4372-b3ac-ea590041ab08','9a10d117-aa76-4d0a-903a-8ba9c82fd499',36,'text','**Mantra tối thượng của Reception OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f35cc1a5-ef72-4e70-aed2-c5da85ea899b','9a10d117-aa76-4d0a-903a-8ba9c82fd499',37,'text','*"Quầy lễ tân là nơi bộ Blouse trắng phô diễn sự tử tế đầu tiên ra ngoài thực địa. Tốc độ, nụ cười và sự thấu cảm của nhân sự tiếp đón chính là chiếc chìa khóa vàng bẻ gãy mọi sự phòng thủ hoài nghi, mở toang cánh cửa lòng tin tuyệt đối của bệnh nhân ngay từ khi họ vừa bước qua bậu cửa phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5b13b491-085b-4ccd-b5a1-a4f389c762d2','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 2: DIAGNOSIS OS - HỆ THỐNG KHÁM, CHẨN ĐOÁN LÂM SÀNG VÀ SỐ HÓA BẰNG CHỨNG Y KHOA','module-2-diagnosis-os-he-thong-kham-chan-oan-lam-sang-va-so-hoa-bang-chung-y-kho',16,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bc394a7c-8e31-426b-b08c-f4fa942dea46','26-clinic-os','5b13b491-085b-4ccd-b5a1-a4f389c762d2',4,'Tư Duy Cốt Lõi: Triệt Tiêu Định Kiến Chủ Quan, Minh Bạch Hóa Lâm Sàng Bằng Dữ Liệu Số','tu-duy-cot-loi-triet-tieu-inh-kien-chu-quan-minh-bach-hoa-lam-sang-bang-du-lieu-',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04dcadec-e090-41d5-bd3b-3b5ffb0ce40c','bc394a7c-8e31-426b-b08c-f4fa942dea46',38,'text','Sai lầm chí mạng của nhiều phòng khám nha khoa truyền thống nằm ở việc vận hành khâu chẩn đoán theo **Hội chứng cảm tính cá nhân**. Một bác sĩ dùng cây thám châm và chiếc gương soi nhỏ, nhìn vào miệng bệnh nhân rồi phán: *"Răng này tiêu xương nặng lắm, phải nhổ cấy Implant"* hoặc *"Hàm này hô phải nhổ 4 răng để niềng"*. Việc đưa ra kết luận y khoa khi thiếu bằng chứng hình ảnh trực quan trực tiếp đẩy bệnh nhân vào trạng thái phòng thủ, hoài nghi rằng phòng khám đang cố tình "vẽ bệnh" để tăng doanh thu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca37192c-e999-44a3-98df-e49366a6584b','bc394a7c-8e31-426b-b08c-f4fa942dea46',39,'text','Tại hệ thống nha khoa hiện tại, đã có sự chuyển dịch tư duy mới: **Chẩn đoán y khoa không phải là một bài diễn văn lý thuyết một chiều. Chẩn đoán là quá trình số hóa bằng chứng khoa học thép để bệnh nhân tự nhìn thấy, tự thấu hiểu và tự ra quyết định điều trị.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7aedf653-a9e0-4448-a02e-b1cc3b823a88','bc394a7c-8e31-426b-b08c-f4fa942dea46',40,'text','Phân hệ **Diagnosis OS** được thiết lập như một bộ lọc kỹ thuật nghiêm ngặt, triệt tiêu hoàn toàn sự biến thiên về mặt năng lực hay tâm trạng giữa các bác sĩ điều trị. Toàn bộ dữ liệu lâm sàng của bệnh nhân tại phòng khám phải được thu thập đầy đủ, minh bạch hóa trên màn hình phân giải cao trước khi đưa ra bất kỳ một chỉ định can thiệp sinh học nào, biến quá trình khám bệnh thành một điểm chạm mỏ neo tối cao của lòng tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4eab149a-2644-4d4c-b94f-759b6013348f','26-clinic-os','5b13b491-085b-4ccd-b5a1-a4f389c762d2',4,'Luồng Vận Hành Tuyến Tính 7 Bước Của Diagnosis OS','luong-van-hanh-tuyen-tinh-7-buoc-cua-diagnosis-os',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0e51452-3246-405b-ae51-8e411e6c8f4a','4eab149a-2644-4d4c-b94f-759b6013348f',41,'text','Mỗi hồ sơ bệnh nhân khi bước từ sảnh tiếp đón của *Reception OS* lên ghế nha bắt buộc phải di chuyển nghiêm ngặt qua trục dọc 7 bước đường ống dưới đây để bảo toàn tính đồng nhất dữ liệu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d5e6e6a-c261-42d5-98cc-9126314d71c9','4eab149a-2644-4d4c-b94f-759b6013348f',42,'image',NULL,'book/26-clinic-os/bbce2d10-88e8-43fe-b199-88a9a8a5d648-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a10b820f-60bb-4e8d-a514-41dfe137e689','26-clinic-os','5b13b491-085b-4ccd-b5a1-a4f389c762d2',4,'Chi Tiết Cấu Trúc Chuẩn Hóa 6 Phân Hệ Nội Dung Lâm Sàng','chi-tiet-cau-truc-chuan-hoa-6-phan-he-noi-dung-lam-sang',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c4e2b8f8-5243-426c-a84f-6859b5a8d6ce','a10b820f-60bb-4e8d-a514-41dfe137e689',43,'text','Để loại bỏ hoàn toàn thói quen làm việc ngẫu hứng, Diagnosis OS đóng gói cấu trúc kỹ thuật cho 6 phân vùng nội dung bắt buộc phải thực thi tại phòng VIP:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fda4a215-3f53-4afc-a5dd-5853f94304e4','a10b820f-60bb-4e8d-a514-41dfe137e689',44,'image',NULL,'book/26-clinic-os/adfbf0fd-096b-44f6-badd-ea0bf14b1737-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91c5852c-0fd1-4f7d-93d5-1e0f4c6b2e54','26-clinic-os','5b13b491-085b-4ccd-b5a1-a4f389c762d2',4,'Bản Đánh Giá Hiệu Suất Diagnosis OS (SLA Performance Checklist)','ban-anh-gia-hieu-suat-diagnosis-os-sla-performance-checklist',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a6017c8-97e6-4461-b35f-f1c25e69460b','91c5852c-0fd1-4f7d-93d5-1e0f4c6b2e54',45,'text','Bảng tiêu chuẩn dưới đây là thước đo bắt buộc để Trưởng phòng lâm sàng hoặc Bác sĩ sáng lập Nguyễn Phước Vinh tiến hành kiểm toán chất lượng chẩn đoán của phòng khám hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5a17ad92-01c3-4c7d-927d-41298dbfb3a9','91c5852c-0fd1-4f7d-93d5-1e0f4c6b2e54',46,'image',NULL,'book/26-clinic-os/9abc245b-70d2-4158-85ef-c3f8d9f91384-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0e60c645-b9e2-41eb-8e8c-c4a29ba26498','26-clinic-os','5b13b491-085b-4ccd-b5a1-a4f389c762d2',4,'Mỏ Neo Toán Học: Chỉ Số Đủ Dữ Liệu Chẩn Đoán (Diagnostic Data Sufficiency Score)','mo-neo-toan-hoc-chi-so-u-du-lieu-chan-oan-diagnostic-data-sufficiency-score',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf488975-1cce-42f3-9c36-d48a7bdd335e','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',47,'image',NULL,'book/26-clinic-os/e10c8114-42e5-40a6-b634-54ea48a0fac9-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84c26a43-370b-4365-baa2-39f1c14a0ddf','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',48,'text','Để triệt tiêu hoàn toàn các ca lỗi do thiếu thông tin lâm sàng, hệ điều hành *Data OS* lập trình công thức toán học đo lường **Chỉ số Đủ Dữ liệu Chẩn đoán (Diagnostic Data Sufficiency Score - DDSS)** của khối lâm sàng hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d510283-a99f-4103-a1b0-f105760a8d5a','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',49,'text','DDSS = \\left( \\frac{\\text{Số lượng hồ sơ bệnh nhân có đủ Phim chụp + Bộ ảnh răng chuẩn SLA}}{\\text{Tổng số lượng bệnh nhân thực tế lên ghế nha thăm khám}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d18c4bde-d73f-40e8-ba87-a88d0b650b36','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',50,'text','**Chỉ số kiểm soát tối cao:** Ngưỡng an toàn pháp định của phòng khám là DDSS \\ge 98\\%. Điều này đảm bảo rằng mọi phác đồ điều trị được xuất xưởng từ nha khoa **Thích Làm Răng** đều được xây dựng trên một nền tảng bằng chứng khoa học thép vững chắc, giúp bảo vệ an toàn sinh học tuyệt đối cho người bệnh và tạo bệ phóng vững chắc cho tỷ lệ đồng ý phác đồ (`Case Acceptance Rate`).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('079c29c1-53ee-4956-917f-4d9565ee865a','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',51,'text','**Mantra tối thượng của Diagnosis OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e93ce3e6-e75f-49c3-b626-4e29624abb84','0e60c645-b9e2-41eb-8e8c-c4a29ba26498',52,'text','*"Đừng bao giờ bắt bệnh nhân phải tin vào những lời nói suông mơ hồ. Hãy cho họ nhìn thấy sự thật về sức khỏe của chính mình thông qua những bằng chứng hình ảnh số hóa minh bạch. Chẩn đoán chuẩn xác và tử tế chính là viên gạch đầu tiên xây dựng nên pháo đài niềm tin bất khả xâm phạm của nha khoa."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3ac2ff07-c577-4eea-9439-f60d650616e7','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 3: TREATMENT PLANNING OS — HỆ THỐNG LẬP KẾ HOẠCH ĐIỀU TRỊ VÀ THIẾT KẾ GIẢI PHÁP Y KHOA MINH BẠCH','module-3-treatment-planning-os-he-thong-lap-ke-hoach-ieu-tri-va-thiet-ke-giai-ph',22,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6ccc3d1d-2f8d-4f06-9897-38383fbd4e36','26-clinic-os','3ac2ff07-c577-4eea-9439-f60d650616e7',4,'Tư Duy Cốt Lõi: Sự Cân Bằng Hoàn Hảo Giữa Y Đức Lâm Sàng Và Tâm Lý Học Chuyển Đổi','tu-duy-cot-loi-su-can-bang-hoan-hao-giua-y-uc-lam-sang-va-tam-ly-hoc-chuyen-oi',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07f1c269-33c3-441f-8636-32d959cd4f78','6ccc3d1d-2f8d-4f06-9897-38383fbd4e36',53,'text','Một trong những điểm nghẽn lớn nhất khiến các ca điều trị giá trị cao (Implant, Chỉnh nha phức tạp, Sứ thẩm mỹ) bị rớt ngay tại ghế nha là do Bác sĩ đang tư vấn theo hai thái cực sai lầm: **Quá nặng tính kỹ thuật y khoa** hoặc **Quá đậm mùi thương mại chèo kéo**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7df1e09-bc8a-4024-9ad1-0e9af5f6af5f','6ccc3d1d-2f8d-4f06-9897-38383fbd4e36',54,'text','Khi Bác sĩ sa đà vào giải thích các thuật ngữ hàn lâm như đường kính ren trụ, mật độ xương hounsfield, hay góc torque răng khôn, bệnh nhân sẽ bị quá tải thông tin và kích hoạt cơ chế phòng thủ trì hoãn: *"Để tôi về suy nghĩ thêm"*. Ngược lại, nếu Chuyên viên tư vấn đẩy mạnh các kỹ thuật ép sale, giảm giá sập sàn, bệnh nhân sẽ lập tức hoài nghi về chất lượng y đức của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('250b026d-3f55-464f-ad44-7d14dbc85fc9','6ccc3d1d-2f8d-4f06-9897-38383fbd4e36',55,'text','Trong hệ điều hành **Dental Empire OS**, phân hệ **Treatment Planning OS** được thiết lập để giải quyết triệt để xung đột này. Chúng tôi định nghĩa: **Một kế hoạch điều trị xuất sắc là một tấm bản đồ tri thức minh bạch, giúp bệnh nhân thấu suốt vấn đề sinh học của bản thân, tự nhìn thấy hậu quả của sự trì hoãn và tự nguyện ra quyết định đầu tư cho sức khỏe.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a98d92e6-7412-4e9a-842a-7e6dd495ab3d','6ccc3d1d-2f8d-4f06-9897-38383fbd4e36',56,'text','Tại nha khoa của bạn, phác đồ điều trị từ Bác sĩ không được viết nguệch ngoạc trên giấy, mà được đóng gói thành một tài sản thông tin cá nhân hóa, bám sát hành vi tâm lý của người bệnh để nâng cao tỷ lệ đồng ý điều trị (`Case Acceptance Rate`) một cách tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c3cfb8af-0356-4ebc-8801-b263bb024740','26-clinic-os','3ac2ff07-c577-4eea-9439-f60d650616e7',4,'Kiến Trúc Thành Phần Của Một Phác Đồ Chuẩn Y Khoa (Treatment Plan Grid)','kien-truc-thanh-phan-cua-mot-phac-o-chuan-y-khoa-treatment-plan-grid',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06b00aab-e5f8-4141-92fd-39596b90812b','c3cfb8af-0356-4ebc-8801-b263bb024740',57,'text','Mỗi kế hoạch điều trị trước khi trình chiếu và bàn giao cho bệnh nhân bắt buộc phải chứa đựng đầy đủ 8 mảnh ghép thông tin cấu trúc dưới đây, xếp theo đúng thứ tự ưu tiên:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6b5b90d4-94e2-4223-86e3-130972e48430','c3cfb8af-0356-4ebc-8801-b263bb024740',58,'image',NULL,'book/26-clinic-os/ffad3f7f-cbe6-4a40-958d-d331f74ddc77-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06105d06-0a24-4fc1-826a-078c9240a7b4','26-clinic-os','3ac2ff07-c577-4eea-9439-f60d650616e7',4,'Quy Trình 5 Giai Đoạn Tư Vấn Dẫn Dắt Tại Phòng VIP (The Consultation Roadmap)','quy-trinh-5-giai-oan-tu-van-dan-dat-tai-phong-vip-the-consultation-roadmap',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6e0ac90-68f0-464e-b38d-70457e0a5080','06105d06-0a24-4fc1-826a-078c9240a7b4',59,'text','Để đưa phác đồ vào tâm trí bệnh nhân một cách mượt mà, Bác sĩ và Chuyên viên điều phối lâm sàng (TCO) thực hiện phối hợp nhịp nhàng theo 5 bước tuyến tính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1320c478-d38f-4f6e-8942-aebdd92e2208','26-clinic-os','06105d06-0a24-4fc1-826a-078c9240a7b4',5,'Giai đoạn 1: Trình chiếu bằng chứng hình ảnh (Visual Evidence):','giai-oan-1-trinh-chieu-bang-chung-hinh-anh-visual-evidence',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5aecb21-da13-4c1a-b3fe-30a3071bdd4d','1320c478-d38f-4f6e-8942-aebdd92e2208',60,'text','Bác sĩ mở phim chụp 3D và bộ ảnh răng lên màn hình lớn. Tuyệt đối không nói suông. Chỉ đích danh vị trí chân răng hỏng hoặc vùng xương bị khuyết thiếu để bệnh nhân trực tiếp quan sát.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c7a970a9-d122-497f-979a-81fa94ec6465','26-clinic-os','06105d06-0a24-4fc1-826a-078c9240a7b4',5,'Giai đoạn 2: Kích hoạt nhận thức rủi ro sinh học (Risk Injection):','giai-oan-2-kich-hoat-nhan-thuc-rui-ro-sinh-hoc-risk-injection',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c954ffe2-a981-4950-9691-9799ea3f5eee','c7a970a9-d122-497f-979a-81fa94ec6465',61,'text','Giải thích cơ chế tàn phá cấu trúc hàm nếu để trống răng hoặc răng lệch lạc quá lâu. Sử dụng các phép ẩn dụ bình dân thường thức để bệnh nhân tự cảm nhận được tính nguy cấp của sức khỏe.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f3140afd-cc91-4686-833a-2821374f045a','26-clinic-os','06105d06-0a24-4fc1-826a-078c9240a7b4',5,'Giai đoạn 3: Thiết kế giải pháp cá nhân hóa (Solution Shaping):','giai-oan-3-thiet-ke-giai-phap-ca-nhan-hoa-solution-shaping',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('77a93ef7-3bc8-4378-adce-ae19d75c9e8e','f3140afd-cc91-4686-833a-2821374f045a',62,'text','Đề xuất phương án can thiệp tối ưu nhất dựa trên nguyên tắc y đức bảo tồn tối đa răng thật. Giải thích công nghệ không đau sinh học (Máng hướng dẫn, sóng siêu âm) để gỡ bỏ nỗi sợ tâm lý cốt lõi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0558c4d2-ee20-49c2-928d-af77d71a4ced','26-clinic-os','06105d06-0a24-4fc1-826a-078c9240a7b4',5,'Giai đoạn 4: Bàn giao Payload tài chính và Phân kỳ lộ trình (TCO Flow):','giai-oan-4-ban-giao-payload-tai-chinh-va-phan-ky-lo-trinh-tco-flow',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b355b397-7db3-4e49-b3a6-5b58a0027adf','0558c4d2-ee20-49c2-928d-af77d71a4ced',63,'text','Chuyển giao vai trò sang cho TCO để bóc tách cấu trúc giá trọn gói. Chia nhỏ dòng tiền theo từng giai đoạn lâm sàng hoặc kích hoạt giải pháp trả góp an toàn 0% qua ngân hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1b9b874f-cddc-4004-b0fb-672011314f8e','26-clinic-os','06105d06-0a24-4fc1-826a-078c9240a7b4',5,'Giai đoạn 5: Khóa hợp đồng cam kết văn bản (Secure Commitment):','giai-oan-5-khoa-hop-ong-cam-ket-van-ban-secure-commitment',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73be5899-f0cf-4671-86d6-3e0ccdf25ff0','1b9b874f-cddc-4004-b0fb-672011314f8e',64,'text','In phác đồ chính thức, ký biên bản cam kết bảo hành chất lượng vật liệu chính hãng, hướng dẫn khách qua quầy kế toán chốt phương án tài chính upfront thu trước và đặt lịch hẹn cho bước lâm sàng đầu tiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('455efcee-97ef-478b-8159-1ada488c81fa','26-clinic-os','3ac2ff07-c577-4eea-9439-f60d650616e7',4,'Khung Kịch Bản Mẫu Thực Chiến Dành Cho Bác Sĩ &amp; TCO','khung-kich-ban-mau-thuc-chien-danh-cho-bac-si-amp-tco',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb5e2279-03fa-4af5-89aa-4ec0740f903f','455efcee-97ef-478b-8159-1ada488c81fa',65,'text','Dưới đây là bản thiết kế ngôn từ được chuẩn hóa, biến bộ khung thô thành một kịch bản giao tiếp thấu cảm và có sức thuyết phục cao tại ghế nha:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5064c145-abb2-4a43-9c6b-a177eadf24c4','455efcee-97ef-478b-8159-1ada488c81fa',66,'text','**BÁC SĨ NGUYỄN PHƯỚC VINH / TCO TRỰC CA:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa00b3b9-0ede-4123-8cc6-65a3a46d76d0','455efcee-97ef-478b-8159-1ada488c81fa',67,'text','"Dạ anh/chị A ơi, qua phim chụp CT Cone Beam 3D và bộ ảnh nội hàm vừa chụp xong, em xin phép chỉ rõ **tình trạng hiện tại** trên màn hình để mình cùng quan sát nhé ạ. Hiện tại vùng răng cấm hàm dưới bên trái của mình đã bị mất hoàn toàn, khoảng trống này đang khiến hai răng kế cận có xu hướng đổ nghiêng vào, còn răng đối diện ở hàm trên thì đang bị trồi xuống do mất lực nâng đỡ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eecc4a54-f53d-4398-b283-4389dbffbf18','455efcee-97ef-478b-8159-1ada488c81fa',68,'text','**Nguyên nhân chính** dẫn đến việc này là do đợt trước mình phải nhổ răng sâu nhưng để trống quá lâu, không làm răng giả cố định sớm. Anh/chị nhìn trên phim chụp 3D này sẽ thấy vùng xương hàm tại vị trí mất răng đang bị lõm xuống đây gọi là hiện tượng tiêu xương hàm sinh học do thiếu lực nhai kích thích ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eed9f7f8-5bdd-4b16-b9a9-d12fc2cb540c','455efcee-97ef-478b-8159-1ada488c81fa',69,'text','**Nếu mình chưa xử lý sớm** mà tiếp tục trì hoãn, trong vòng 6 tháng tới, vùng xương này sẽ tiêu biến sâu hơn, làm sụt lún cơ mặt gây lão hóa sớm. Nguy hiểm hơn, các răng xung quanh sẽ bị xô lệch nghiêm trọng, làm hỏng toàn bộ khớp cắn và gây đau khớp thái dương hàm, lúc đó việc ăn nhai hằng ngày của mình sẽ cực kỳ khó khăn và đau buốt ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e93523a-d0dd-4493-9e6c-a38d69c4a1c2','455efcee-97ef-478b-8159-1ada488c81fa',70,'text','**Phương án phù hợp và an toàn nhất** cho mình lúc này là tiến hành cấy ghép một trụ Implant chính hãng châu Âu để khôi phục lại chiếc chân răng đã mất, giúp bảo tồn nguyên vẹn xương hàm và không phải mài nhỏ hai răng thật bên cạnh. Để mình hoàn toàn yên tâm, công nghệ bên em sẽ sử dụng máng hướng dẫn phẫu thuật kỹ thuật số, cấy trụ chính xác đến từng milimet, hậu phẫu cực kỳ nhẹ nhàng, không sưng đau sinh học đâu ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da89c801-3480-446c-8f35-f85824080cd3','455efcee-97ef-478b-8159-1ada488c81fa',71,'text','Để thuận tiện cho mình, em đã thiết kế lộ trình này **chia thành 2 giai đoạn** rất rõ ràng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c82bbf8-c2ff-417a-bcfb-eb1e859a9888','455efcee-97ef-478b-8159-1ada488c81fa',72,'text','- **Giai đoạn ưu tiên nhất (Hôm nay):** Bác sĩ sẽ vệ sinh vùng nướu, xử lý ổ viêm và nhẹ nhàng đặt trụ Implant vào xương hàm. Quá trình này chỉ mất khoảng 15 phút thôi ạ.- **Giai đoạn 2 (Sau 3 tháng):** Khi trụ đã tích hợp xương vững chắc, Bác sĩ sẽ tiến hành lắp chiếc răng sứ thẩm mỹ lên trên để hoàn tất chức năng ăn nhai trọn vẹn cho mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15839751-eb14-4052-aeee-0f1aff42f983','455efcee-97ef-478b-8159-1ada488c81fa',73,'text','Về bài toán dòng tiền, **chi phí dự kiến trọn gói** cho toàn bộ lộ trình này là [Số tiền minh bạch], cam kết bằng văn bản không phát sinh bất kỳ chi phí ẩn nào trong suốt quá trình điều trị. Đặc biệt, nha khoa bên em hỗ trợ chia nhỏ thanh toán: Hôm nay mình chỉ cần đóng trước 50% chi phí phần trụ, phần răng sứ còn lại mình sẽ trả dần sau 3 tháng hoặc chọn phương án trả góp 0% qua ngân hàng liên kết để hoàn toàn thoải mái về mặt tài chính gia đình ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('063b6b91-b6e5-4de6-8cac-b84936470e67','455efcee-97ef-478b-8159-1ada488c81fa',74,'text','**Sau điều trị**, hệ thống Patient OS của phòng khám sẽ chịu trách nhiệm chăm sóc mình trọn đời: Định kỳ 6 tháng một lần, bộ phận CSKH sẽ nhắn tin nhắc lịch hẹn để mời anh/chị qua phòng khám kiểm tra tốc độ tích hợp xương, cạo vôi răng bảo trì hoàn toàn miễn phí, đảm bảo chiếc răng mới đồng hành cùng sức khỏe của mình lâu dài nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4926c563-4061-4ef4-8488-7f6d5c4ac73f','455efcee-97ef-478b-8159-1ada488c81fa',75,'text','Dạ với lộ trình rõ ràng và giải pháp tài chính linh hoạt như vậy, đã giúp anh/chị sẵn sàng để Bác sĩ Vinh tiến hành bước nhẹ nhàng đầu tiên giải cứu chiếc răng cấm cho mình ngay hôm nay chưa ạ?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35a2f854-4554-4102-8b20-6c1f20a66107','455efcee-97ef-478b-8159-1ada488c81fa',76,'text','- **Chỉ Số Quản Trị: Tỷ Lệ Chấp Thuận Phác Đồ (Case Acceptance Rate)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abfdf0df-1642-4268-8fda-d68d2bba8a44','455efcee-97ef-478b-8159-1ada488c81fa',77,'image',NULL,'book/26-clinic-os/32ec95b3-86ae-4ca3-9b41-2779912f9028-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('230e23ac-1df7-4ff8-9398-5b8e9240e095','455efcee-97ef-478b-8159-1ada488c81fa',78,'text','Hệ điều hành đánh giá năng lực tư vấn y khoa và độ bén chuyển đổi của phân hệ Treatment Planning OS thông qua phương trình toán học quản trị tối cao:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a302bc6c-36ac-4606-92e1-f19eabfc6539','455efcee-97ef-478b-8159-1ada488c81fa',79,'text','CAR = \\left( \\frac{\\text{Số lượng phác đồ được bệnh nhân ký duyệt và đóng tiền upfront}}{\\text{Tổng số lượng kế hoạch điều trị được xuất bản thực tế tại ghế nha}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f33a719-0173-4015-9941-93ddaafea23c','455efcee-97ef-478b-8159-1ada488c81fa',80,'text','- **Ngưỡng mục tiêu vận hành (SLA Benchmark):** Đối với các dòng dịch vụ mũi nhọn giá trị cao tại thị trường Hà Nội, chỉ số CAR bắt buộc phải được kiểm soát đạt mốc **\\ge**** 65%**.- **Hành động sửa sai (Action Plan):** Nếu chỉ số CAR tụt xuống dưới 50% hằng tuần, chứng tỏ nhân sự đang mắc lỗi sàn: Hoặc Bác sĩ nói quá nhiều thuật ngữ kỹ thuật gây sợ hãi, hoặc TCO đưa ra phương án tài chính quá nặng nề mà không kích hoạt đòn bẩy trả góp để phá vỡ rào cản dòng tiền cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('763bc13d-8e71-4eb9-a667-08994ef85376','26-clinic-os','3ac2ff07-c577-4eea-9439-f60d650616e7',4,'Bộ Đầu Ra Tài Liệu Tiêu Chuẩn Đóng Gói (Deliverables Bundle)','bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fe7dcaf-7b02-485b-a019-6eb7ac07d0b2','763bc13d-8e71-4eb9-a667-08994ef85376',81,'text','Để cấu phần Treatment Planning OS được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn của nha khoa, khối lâm sàng bắt buộc phải đóng gói thành công bộ 5 tài sản quản trị sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73a7de6e-a2f2-4e37-85d5-e801e009c071','763bc13d-8e71-4eb9-a667-08994ef85376',82,'text','- **Standardized Treatment Plan PDF Template:** Biểu mẫu số hóa thiết kế phác đồ điều trị chuyên nghiệp, hiển thị trực quan 8 thành phần cấu trúc để in ấn và ký kết biên bản với khách hàng.- **Patient-Facing Analogy Guide Book:** Cuốn sổ tay lưu trữ các phép ẩn dụ, giải thích bệnh lý bằng ngôn từ bình dân thường thức dành cho đội ngũ Bác sĩ trẻ và nhân sự TCO học thuộc lòng.- **High-Ticket Phasing & Cost Calculator:** Công cụ Excel tự động phân rã dòng tiền mặt và lập lịch chia nhỏ thanh toán theo tiến độ lâm sàng cho từng dòng trụ Implant và khay niềng Invisalign.- **Clinical-to-TCO Handover SOP:** Văn bản quy định quy chuẩn bàn giao tín hiệu ngầm và Payload dữ liệu tâm lý của bệnh nhân từ Bác sĩ sang cho Chuyên viên điều phối tài chính tại phòng VIP.- **Risk Matrix Catalog for Non-Treatment:** Bộ tư liệu hình ảnh và video khoa học minh họa trực quan các biến chứng nguy hiểm của việc trì hoãn điều trị để làm vũ khí bẻ gãy tâm lý hoãn ra quyết định của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7221762-7303-41f4-8219-df44649c84b5','763bc13d-8e71-4eb9-a667-08994ef85376',83,'text','**Mantra tối thượng của Treatment Planning OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c9af0ac-2585-4de7-bcea-3a9531fa4f1e','763bc13d-8e71-4eb9-a667-08994ef85376',84,'text','*"Đừng cố gắng bán một dịch vụ nha khoa đắt đỏ bằng các thủ thuật thương mại. Hãy trao cho bệnh nhân một kế hoạch điều trị tràn đầy sự minh bạch và tính thấu cảm y khoa. Khi nỗi sợ hãi về biến chứng tương lai đè bẹp hoàn toàn rào cản về chi phí hiện tại, bệnh nhân sẽ tự động xuống tiền trong sự biết ơn sâu sắc."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e190bf97-ea9b-4d8b-9e2f-7164c24a632f','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 4: CHAIRSIDE OPERATION OS — HỆ THỐNG ĐIỀU PHỐI GHẾ NHA VÀ TỐI ƯU HÓA NĂNG SUẤT LÂM SÀNG SÀN','module-4-chairside-operation-os-he-thong-ieu-phoi-ghe-nha-va-toi-uu-hoa-nang-sua',33,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('53a406d4-afad-459e-9adf-bf814329aac8','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Tư Duy Cốt Lõi: Công Nghiệp Hóa Ghế Điều Trị, Triệt Tiêu Thời Gian Chết Và Lỗi Phối Hợp','tu-duy-cot-loi-cong-nghiep-hoa-ghe-ieu-tri-triet-tieu-thoi-gian-chet-va-loi-phoi',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdd419c5-a144-40fa-8ecb-6e0255ff76e6','53a406d4-afad-459e-9adf-bf814329aac8',85,'text','Trận chiến thực sự quyết định năng lực sinh lời và uy tín y đức của một phòng khám RHM diễn ra ngay tại không gian **Bán kính 2 mét xung quanh chiếc ghế nha**. Nhiều nha khoa hiện nay đang vận hành khu vực ghế điều trị theo kiểu thủ công và bản năng: Bác sĩ bước vào phòng khám mới hỏi phụ tá ca này làm gì, phụ tá lóng ngóng đi tìm vật liệu khi đang điều trị, kho hết hàng đột xuất, lễ tân xếp lịch chồng chéo khiến bệnh nhân phải nằm chờ đợi dài cổ trên ghế trong sự mệt mỏi. Sự rời rạc này không chỉ làm giảm sụt trải nghiệm Wow của khách hàng mà còn trực tiếp gây ra các rủi ro sai sót lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f096eb02-d5fb-4700-b6b2-2ea4df1b3025','53a406d4-afad-459e-9adf-bf814329aac8',86,'text','Trong hệ điều hành **Dental Empire OS**, chiếc ghế nha được định vị là **Một nhà máy sản xuất giải pháp y khoa mini**. Năng suất của nhà máy này không phụ thuộc vào sự ngẫu hứng của con người, mà được lập trình cơ học thông qua phân hệ **Chairside Operation OS**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00ae4b98-d8be-443a-91bb-b87ff9fd0caa','53a406d4-afad-459e-9adf-bf814329aac8',87,'text','Hệ điều hành này chịu trách nhiệm đồng bộ hóa thời gian thực và quản trị không ma sát giữa 5 bánh răng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('943a589a-7468-4b8a-9913-19b47abcedd1','53a406d4-afad-459e-9adf-bf814329aac8',88,'text','- *Lịch đặt hẹn (Sales OS)* - *Hồ sơ bệnh án điện tử (Data OS)* - *Hạ tầng thiết bị (Clinic OS)* - *Vật tư tiêu hao (Kho/Supply Chain)* - *Năng lực thực thi (Bác sĩ & Trợ thủ)*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('471243d0-191a-4f1f-8318-84f1622b1a2d','53a406d4-afad-459e-9adf-bf814329aac8',89,'text','Mục tiêu tối hậu là đảm bảo mỗi ca điều trị (đặc biệt là các ca cấy ghép Implant chuyên sâu hay chỉnh nha) diễn ra chuẩn xác đến từng milimet, đúng thời hạn định mức, an toàn  tuyệt đối và triệt tiêu hoàn toàn mọi lỗi ma sát phối hợp nội bộ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed0922c8-54a2-4951-8f19-81f2940b01e0','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Ma Trận 10 Yếu Tố Kiểm Soát Tối Cao Tại Ghế Điều Trị (Chairside Control Matrix)','ma-tran-10-yeu-to-kiem-soat-toi-cao-tai-ghe-ieu-tri-chairside-control-matrix',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c62b3c48-cddf-494d-a5de-c6bb9bbb76d3','ed0922c8-54a2-4951-8f19-81f2940b01e0',90,'text','Để một ca lâm sàng được xuất xưởng hoàn hảo, Chairside Operation OS thiết lập rào cản kỹ thuật kiểm soát nghiêm ngặt 10 biến số cốt lõi dưới đây hằng ngày:',NULL,NULL,NULL,NULL,NULL);
