INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('08dbdba4-a51d-419a-a7c8-025738a6f464','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Quy Trình Đường Ống Vận Hành Ghế Nha 9 Bước (The Chairside Pipeline)','quy-trinh-uong-ong-van-hanh-ghe-nha-9-buoc-the-chairside-pipeline',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a038ce1c-19c6-44b3-8280-0ce17173c7b7','08dbdba4-a51d-419a-a7c8-025738a6f464',92,'text','Mọi ca can thiệp lâm sàng tại nha khoa bắt buộc phải được nhân sự vận hành tuần tự theo đúng trục dọc 9 bước đường ống khép kín dưới đây để bảo đảm tính an toàn sinh học tối cao:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f748e731-aeef-43df-9505-88eac8d59a28','08dbdba4-a51d-419a-a7c8-025738a6f464',93,'text','***Trước giờ hẹn 30 phút: *****Xác phần lịch điều trị hệ thống:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('33ebeabb-9b32-4406-91a7-4c9337df66a1','08dbdba4-a51d-419a-a7c8-025738a6f464',94,'text','Điều phối viên sàn trích xuất danh sách bệnh nhân của ca trực, kiểm tra các mã lịch hẹn trạng thái `Confirmed` để sẵn sàng kích hoạt nguồn lực sàn vật lý.',NULL,NULL,NULL,NULL,NULL);
