INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('68389c37-5698-420b-92bd-6c08e9cde4cf','08dbdba4-a51d-419a-a7c8-025738a6f464',96,'text','Phụ tá tiến hành sát khuẩn bề mặt da ghế, tay xịt hơi, hệ thống đèn chiếu bằng dung dịch chuyên dụng; bọc màng nylon bảo vệ tại các điểm chạm để triệt tiêu nguy cơ lây nhiễm chéo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f41f6eed-285c-4013-af53-2adc28bb2070','08dbdba4-a51d-419a-a7c8-025738a6f464',97,'text','***Trước khi khách vào 5 phút:***** Setup khay dụng cụ và Vật tư tiêu hao:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f571345-bf9e-4d6d-b407-a90b2ae722fd','08dbdba4-a51d-419a-a7c8-025738a6f464',98,'text','Trợ thủ thực hiện mở niêm phong gói dụng cụ vô trùng, setup khay phẫu thuật theo đúng dịch vụ mũi nhọn quan tâm của ca, chuẩn bị sẵn vật liệu chính hãng châu Âu đúng thông số phác đồ.',NULL,NULL,NULL,NULL,NULL);
