INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('beaea63b-6d68-431f-ab7d-2754e088b809','08dbdba4-a51d-419a-a7c8-025738a6f464',100,'text','Bác sĩ và Phụ tá cùng mở màn hình CRM đầu ghế nha, đọc lại ghi chú Payload dữ liệu của Sales Online, xem phim CT Cone Beam để nắm chắc đặc điểm tâm lý (sợ đau sinh học) và tiến độ điều trị của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c55107a-1284-4851-8a4d-50c780937f09','08dbdba4-a51d-419a-a7c8-025738a6f464',101,'text','***Mốc thời gian hẹn thực tế: *****Đón tiếp bệnh nhân lên ghế điều trị:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97298791-f493-45de-88cd-45245f76867e','08dbdba4-a51d-419a-a7c8-025738a6f464',102,'text','Phụ tá ra sảnh chờ VIP đón khách bằng nụ cười thấu cảm, điều hướng khách lên ghế nha, thắt khăn che ngực bảo vệ và điều chỉnh tư thế ghế đạt độ thoải mái sinh học cao nhất cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0389fa41-ec58-4fbe-b3ca-ebb660edea77','08dbdba4-a51d-419a-a7c8-025738a6f464',103,'text','***Thời gian can thiệp lâm sàng: *****Thực thi thủ thuật y khoa bốn tay (Four-Handed):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('073f3716-c44a-4bf5-83b8-7e67cf0851db','08dbdba4-a51d-419a-a7c8-025738a6f464',104,'text','Bác sĩ Vinh cùng đội ngũ tiến hành can thiệp phẫu thuật/thủ thuật. Áp dụng nghiêm ngặt kỹ thuật nha khoa bốn tay: Bác sĩ tập trung 100% mắt và tay vào khoang miệng bệnh nhân; Phụ tá chủ động truyền nhận dụng cụ, hút nước bọt liên tục để giảm ma sát và thời gian nằm ghế cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa1720da-6039-4bfd-8057-863dc36487e0','08dbdba4-a51d-419a-a7c8-025738a6f464',105,'text','***Thực hiện song song tại ghế: *****Ghi nhận dữ liệu số thời gian thực:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2113abb2-fb4b-4f68-8c68-41e820e9ee3e','08dbdba4-a51d-419a-a7c8-025738a6f464',106,'text','Phụ tá thực hiện nhập liệu các thông số vật liệu tiêu hao thực tế (Mã vạch trụ Implant, loại chỉ khâu, thông số khay niềng) và tiến trình lâm sàng trực tiếp vào phần mềm CRM ngay tại ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a66c7cc-098f-4bdb-b24f-9ed23f1e5a91','08dbdba4-a51d-419a-a7c8-025738a6f464',107,'text','***Trước khi khách rời ghế:***** Bác sĩ dặn dò hậu phẫu trực quan:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c199b7c4-f471-490e-b74a-cf22a47515ba','08dbdba4-a51d-419a-a7c8-025738a6f464',108,'text','Bác sĩ hạ ghế, trực tiếp giải thích kết quả ca điều trị hôm nay qua màn hình đối diện, đưa ra lời dặn dò chế độ dinh dưỡng, dập tắt nỗi sợ biến chứng bằng thái độ ân cần, y đức.',NULL,NULL,NULL,NULL,NULL);
