INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('18b6a896-6127-473d-ba47-d85c8c41dc70','08dbdba4-a51d-419a-a7c8-025738a6f464',110,'text','Phụ tá dẫn bệnh nhân ra quầy Lễ tân, bàn giao Payload hồ sơ cứng kèm lời dặn nội bộ để kích hoạt luồng thanh toán tài chính và luồng tin nhắn dặn dò hậu phẫu tự động của Patient OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6e5bee63-5b35-4686-b945-83fdd6b194c2','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Bảng Checklist Tiền Điều Trị Chuẩn SLA (Pre-Treatment Audit Checklist)','bang-checklist-tien-ieu-tri-chuan-sla-pre-treatment-audit-checklist',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a2b572b-0ac1-4871-a1a6-7592a1352024','6e5bee63-5b35-4686-b945-83fdd6b194c2',111,'text','Tuyệt đối nghiêm cấm hành vi đưa bệnh nhân vào điều trị khi chưa hoàn tất kiểm toán hạ tầng. Trước khi Bác sĩ đặt mũi khoan hoặc dụng cụ vào miệng khách hàng, Trợ thủ nha khoa bắt buộc phải tích dấu nghiệm thu 100% các hạng mục kiểm soát sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('99970c8f-0cc9-4cf9-a540-98be5a1b099c','6e5bee63-5b35-4686-b945-83fdd6b194c2',112,'image',NULL,'book/26-clinic-os/378cc86a-2a3f-426e-870b-4405d72a3fba-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1441cf4e-a898-4ecf-a744-33f3adf365a9','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Mỏ Neo Quản Trị: Phương Trình Tối Ưu Hóa Chu Kỳ Xoay Vòng Ghế Nha (Chair Turnaround Time)','mo-neo-quan-tri-phuong-trinh-toi-uu-hoa-chu-ky-xoay-vong-ghe-nha-chair-turnaroun',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee1c7489-1fb3-49d6-bbf3-592fe2c801d5','1441cf4e-a898-4ecf-a744-33f3adf365a9',113,'image',NULL,'book/26-clinic-os/c07af4ef-da54-46a5-8a3e-453613de0db0-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6a54a7d-c575-49ed-9a61-a7e4442c9d79','1441cf4e-a898-4ecf-a744-33f3adf365a9',114,'text','- *Ý nghĩa quản trị:* Nếu CIL > 0 (Ví dụ CIL = 15 phút), điều này chứng minh bộ máy sàn đang bị lãng phí mất 15 phút "ghế chết" không sản sinh ra doanh thu do lỗi điều phối lóng ngóng của lễ tân hoặc tốc độ dọn phòng quá chậm của phụ tá. Ban giám đốc nhìn vào chỉ số này để kịp thời căn chỉnh năng suất lao động hằng tuần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4de12a51-00a9-4d6d-99c0-47f6657a1449','26-clinic-os','e190bf97-ea9b-4d8b-9e2f-7164c24a632f',4,'Bộ Đầu Ra Tài Liệu Tiêu Chuẩn Đóng Gói (Deliverables Bundle)','bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a86b0a9c-090e-44b3-860d-8df6305db0c9','4de12a51-00a9-4d6d-99c0-47f6657a1449',115,'text','Để cấu phần Chairside Operation OS được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành lâu dài cho phòng khám, ban điều hành bắt buộc phải đóng gói thành công bộ 5 tài sản quản trị sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee73701b-ca9c-44ab-9399-3086cb3b570f','4de12a51-00a9-4d6d-99c0-47f6657a1449',116,'text','- **Chairside Master Operation SOP:** Cuốn cẩm nang quy định chi tiết bộ tiêu chuẩn kỹ thuật vận hành, bảo trì thiết bị ghế nha và hệ thống màn hình điều phối thời gian thực.- **Standardized Surgical Tray Setup Manual:** Tài liệu hình ảnh atlas hướng dẫn phụ tá cách sắp xếp khay dụng cụ vô trùng chuẩn xác cho từng dòng dịch vụ: Khay phẫu thuật Implant, khay gắn mắc cài, khay mài bọc sứ.- **Four-Handed Dentistry Behavioral SLA:** Bản đặc tả kỹ thuật phối hợp hành vi ngôn ngữ cơ thể và tín hiệu ngầm giữa Bác sĩ và Trợ thủ theo mô hình nha khoa bốn tay đẳng cấp quốc tế.- **Pre-Treatment Digital Audit Logger:** Cấu hình biểu mẫu check-list điện tử tích hợp trên máy tính bảng đầu ghế nha, bắt buộc phụ tá phải tích duyệt trực tuyến trước khi điều trị.- **Post-Surgical Clinical Handover Template:** Mẫu biên bản Payload số hóa ghi nhận vật liệu tiêu hao và thông số lâm sàng tại ghế để bàn giao thông tin mượt mà sang phân hệ chăm sóc hậu phẫu của Patient OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('95993dfd-1382-4b25-82b3-a06bdc18be85','4de12a51-00a9-4d6d-99c0-47f6657a1449',117,'text','**Mantra tối thượng của Chairside Operation OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9945063-e200-4f98-ab65-a59e6236b308','4de12a51-00a9-4d6d-99c0-47f6657a1449',118,'text','*"Chiếc ghế nha chính là thánh đường nơi y đức của Bác sĩ được hiện thực hóa bằng điều trị chuyên môn. Hãy quản trị không gian đó bằng tính kỷ luật công nghiệp tuyệt đối, triệt tiêu mọi giây phút lãng phí để mang lại sự an toàn trọn vẹn và trải nghiệm Wow đỉnh cao cho bệnh nhân."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('14d88770-6561-40d7-9f77-52e02c9555de','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 5: TREATMENT QUALITY OS - HỆ THỐNG KIỂM SOÁT CHẤT LƯỢNG ĐIỀU TRỊ VÀ BẢO CHỨNG Y ĐỨC LÂM SÀNG','module-5-treatment-quality-os-he-thong-kiem-soat-chat-luong-ieu-tri-va-bao-chung',40,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('32c6a184-1de0-4a36-8f4d-5e4649cac3f8','26-clinic-os','14d88770-6561-40d7-9f77-52e02c9555de',4,'Tư Duy Cốt Lõi: Y Khoa Không Có Chỗ Cho "Rút Kinh Nghiệm", Số Hóa Hàng Rào Kiểm Soát Lâm Sàng','tu-duy-cot-loi-y-khoa-khong-co-cho-cho-rut-kinh-nghiem-so-hoa-hang-rao-kiem-soat',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff17b2f5-5bb9-4a13-acaa-eaae45a983e1','32c6a184-1de0-4a36-8f4d-5e4649cac3f8',119,'text','Trong kinh doanh nha khoa, nếu *Marketing OS* mang lại dòng khách và *Sales OS* mang lại dòng tiền, thì chính **Treatment Quality OS (Hệ thống kiểm soát chất lượng điều trị)** mới là phân hệ quyết định sự sống còn, danh tiếng trường tồn và năng lực giữ chân khách hàng của phòng khám. Một sai lầm chí mạng của các nha khoa truyền thống là buông lỏng tiêu chuẩn lâm sàng, phó mặc hoàn toàn chất lượng điều trị vào tay nghề và tâm trạng ngày hôm đó của từng bác sĩ. Khi xảy ra biến chứng như trụ Implant bị đào thải do cấy sai hướng, răng sứ bị hở đường hoàn tất gây viêm nướu, hay răng chạy lệch sau niềng do sai lực phòng khám sẽ phải đối mặt với thảm họa khủng hoảng truyền thông và chi phí đền bù tổn thất cực kỳ nặng nề.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8870cb1-01d6-4e4b-a90e-43e2604f4cf5','32c6a184-1de0-4a36-8f4d-5e4649cac3f8',120,'text','Hệ điều hành **Dental Empire OS** thiết lập một nguyên lý thượng tầng: **Y khoa là ngành khoa học chính xác, tuyệt đối không vận hành bằng sự cảm tính hay các bài học rút kinh nghiệm sau sai sót. Chất lượng điều trị phải được kiểm soát chủ động bằng hàng rào kỹ thuật cứng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('450bc413-988c-4f66-ad6c-ecb07b59133f','32c6a184-1de0-4a36-8f4d-5e4649cac3f8',121,'text','Phân hệ *Treatment Quality OS* đóng vai trò là "Bộ kiểm toán lâm sàng độc lập". Phân hệ này tối ưu hóa toàn bộ các bước can thiệp sinh học tại ghế nha, đảm bảo đội ngũ y bác sĩ không chỉ làm nhanh hằng ngày, mà phải **làm đúng, làm đều tay và làm dưới sự giám sát nghiêm ngặt**. Từ đó, biến năng lực chuyên môn của Bác sĩ cùng cộng sự thành một hệ thống tiêu chuẩn hóa, triệt tiêu 100% rủi ro chuyên môn và biến mỗi ca lâm sàng thành một tài sản bảo chứng thương hiệu y khoa tử tế vững chắc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0afcd0a4-f538-4030-bd43-f8e1dfad5a8b','26-clinic-os','14d88770-6561-40d7-9f77-52e02c9555de',4,'Năm Lớp Kiểm Soát Chất Lượng Đồng Bộ (The 5-Layer Quality Shield)','nam-lop-kiem-soat-chat-luong-ong-bo-the-5-layer-quality-shield',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('419d0b72-5183-491e-8be8-2ee221598e50','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',122,'text','Để bảo vệ an toàn sinh học tuyệt đối cho bệnh nhân tại phòng khám mọi ca điều trị bắt buộc phải đi qua hệ thống phòng ngự 5 lớp bọc lót tuyến tính khép kín dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1a0b889-fa13-4bce-a822-bb4086fef2a8','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',123,'text','***Lớp phòng ngự 1:***** Kiểm tra trước điều trị (Pre-Treatment Auditing):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cfb08574-47e0-4e8a-ba07-9341f33d9e8a','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',124,'text','Hội đồng chuyên môn thực hiện thẩm định tính pháp lý và độ chuẩn xác của hồ sơ: Đối soát phim chụp 3D CT Cone Beam, phê duyệt thiết kế máng hướng dẫn phẫu thuật, và kiểm tra chữ ký cam kết đồng ý phác đồ của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e97aae0b-4b70-40e8-8c08-3633ce985640','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',125,'text','***Lớp phòng ngự 2:***** Giám sát trong điều trị (Intra-Treatment Monitoring):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7035a3ca-19e0-4e88-923b-6272fcc714a5','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',126,'text','Kiểm soát nghiêm ngặt môi trường vô trùng phòng phẫu thuật VIP, áp dụng kỹ thuật nha khoa bốn tay (Four-handed dentistry) để phụ tá giám sát chéo từng thao tác đi mũi khoan, đo lực torque đặt trụ Implant của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b87a6d7-050f-482e-99fb-0f63df9b76a6','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',127,'text','***Lớp phòng ngự 3:***** Nghiệm thu ngay sau điều trị (Post-Treatment Validation):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84601319-2c7d-4a52-87ea-437066ecb9d4','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',128,'text','Tiến hành chụp phim X-quang kiểm tra tại ghế nha ngay sau khi hoàn tất thủ thuật để nghiệm thu độ khít sát của đường hoàn tất răng sứ, hướng đi của trụ Implant hoặc vị trí đặt minivis. Ghi nhận chỉ số sinh hiệu đầu ra của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e8b17d43-c6f7-453e-bec2-28687759d2a8','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',129,'text','***Lớp phòng ngự 4:***** Theo dõi chu kỳ tái khám (Recall Clinical Audit):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5f4c82f-6ba3-4120-9655-f31c44763ce7','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',130,'text','Kích hoạt lịch hẹn kiểm tra cắt chỉ, đo độ tích hợp xương (ISQ) hoặc căn chỉnh lực siết dây cung chỉnh nha định kỳ. Bác sĩ trực ca đánh giá tốc độ lành thương mô mềm và phản ứng sinh học của nướu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('758c85ca-e937-44eb-bbca-496b8bb658b8','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',131,'text','***Lớp phòng ngự 5:***** Đánh giá kết quả cuối cùng (Final Clinical Evaluation):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('023ae39d-b5f3-4990-a799-7855b225f692','0afcd0a4-f538-4030-bd43-f8e1dfad5a8b',132,'text','Khi hoàn tất toàn bộ lộ trình phác đồ, thực hiện đối soát bộ ảnh răng DSLR Trước - Sau, kiểm toán toàn bộ nhật ký bệnh án điện tử (EMR) và ký biên bản nghiệm thu, cấp thẻ bảo hành chính hãng văn bản cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('475affda-6004-4d16-ae1e-25ac2eefb965','26-clinic-os','14d88770-6561-40d7-9f77-52e02c9555de',4,'Ma Trận Bảng Checklist Chất Lượng Đầu Ra (The Master Quality Checklist)','ma-tran-bang-checklist-chat-luong-au-ra-the-master-quality-checklist',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92f1dc8e-db94-438e-b66f-16d2d8e4cf53','475affda-6004-4d16-ae1e-25ac2eefb965',133,'text','Để loại bỏ hoàn toàn thói quen làm việc cẩu thả hoặc bỏ bớt bước lâm sàng của nhân sự, *Treatment Quality OS* quy định bộ Checklist 8 điểm neo bắt buộc phải số hóa 100% trên phần mềm quản trị hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1386fe4d-d416-44de-be8f-657b84db8154','26-clinic-os','14d88770-6561-40d7-9f77-52e02c9555de',4,'Phương Trình Đo Lường Tỷ Lệ Tuân Thủ Chất Lượng Lâm Sàng (CQCR)','phuong-trinh-o-luong-ty-le-tuan-thu-chat-luong-lam-sang-cqcr',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1aeeba3-5a94-4661-991d-0d5fdf1eefea','1386fe4d-d416-44de-be8f-657b84db8154',134,'image',NULL,'book/26-clinic-os/0199234b-b254-4fec-bd43-0af12cfdb49a-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04cb6274-b2fd-479b-9633-62ed1e8a481d','1386fe4d-d416-44de-be8f-657b84db8154',135,'text','Để định lượng chính xác năng lực kiểm soát chất lượng và không cho phép bất kỳ ca lỗi sàn nào được che giấu, hệ điều hành *Data OS* áp dụng phương trình toán học quản trị tối cao đo lường **Chỉ số Tuân thủ Chất lượng Lâm sàng (Clinical Quality Compliance Rate - CQCR)** hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c79666ce-15d5-4977-bd48-69fc708c634d','1386fe4d-d416-44de-be8f-657b84db8154',136,'text','\\text{CQCR (\\%)} = \\left( \\frac{N_{\\text{Compliant}}}{N_{\\text{Total}}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1affe976-105b-429c-80d3-28411786015e','1386fe4d-d416-44de-be8f-657b84db8154',137,'text','*In đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1511c42a-f9b9-42b7-86bc-8db4cdb675c2','1386fe4d-d416-44de-be8f-657b84db8154',138,'text','- N_{\\text{Compliant}}: Số lượng hồ sơ bệnh nhân hoàn tất điều trị đạt điểm tích duyệt tuyệt đối 8/8 mục tiêu trên bảng Master Quality Checklist.- N_{\\text{Total}}: Tổng số lượng bệnh nhân thực tế đã thực hiện thủ thuật/phẫu thuật lâm sàng trong tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd50bca1-11fc-4dbc-ac51-e278e1e8d088','1386fe4d-d416-44de-be8f-657b84db8154',139,'text','**Chỉ số kiểm soát tối cao của Dental Empire OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3af308b9-a1be-4031-85c0-6722e292e126','1386fe4d-d416-44de-be8f-657b84db8154',140,'text','Tiêu chuẩn nghiệm thu vận hành bắt buộc phải đạt \\text{CQCR} \\ge 99\\%. Đồng thời, tỷ lệ biến chứng sinh học hoặc khiếu nại chuyên môn sau điều trị phải kiểm soát nghiêm ngặt ở mức dưới 1\\%. Bất kỳ Bác sĩ hoặc Trợ thủ nào để chỉ số tuân thủ hệ thống tụt xuống dưới ngưỡng an toàn sẽ lập tức bị đình chỉ năng lực thực thi ca lớn và đưa vào luồng đào tạo lại quy trình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c6e842a1-f26b-46bb-8d73-ab064184640e','26-clinic-os','14d88770-6561-40d7-9f77-52e02c9555de',4,'Bộ Đầu Ra Tài Liệu Tiêu Chuẩn Đóng Gói (Deliverables Bundle)','bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65806375-5979-4a5a-9c81-cd838dfa5097','c6e842a1-f26b-46bb-8d73-ab064184640e',141,'text','Để phân hệ Treatment Quality OS được nghiệm thu hoàn tất và đóng gói thành tài sản mã nguồn vận hành dài hạn cho phòng khám, ban điều hành bắt buộc phải hoàn thiện bộ 5 tài sản quản trị số hóa sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1473faa-a1db-4567-a2f0-51a0779d6dbd','c6e842a1-f26b-46bb-8d73-ab064184640e',142,'text','- **Master Clinical Quality Guideline:** Cuốn sổ tay quy chuẩn kỹ thuật lâm sàng tối thiểu cho từng dòng dịch vụ mũi nhọn (Implant, Chỉnh nha, Răng sứ), quy định rõ các giới hạn an toàn sinh học pháp định.- **Sterilization & Infection Control SOP:** Văn bản quy trình kiểm soát nhiễm khuẩn khép kín chuẩn Class B, quy định nghiêm ngặt chu kỳ hấp sấy, dán nhãn chỉ thị màu và test vi sinh định kỳ thiết bị.- **Digital EMR Audit Log System:** Cấu hình biểu mẫu kiểm toán bệnh án điện tử tự động trên CRM, chặn không cho phép đóng hồ sơ nếu thiếu phim đối soát đầu ra.- **Clinical Peer-Review Protocol:** Quy chế thành lập hội đồng chuyên môn và biên bản tổ chức các buổi hội chẩn, mổ xẻ ca lâm sàng lỗi hằng tuần để nâng cao năng lực đội ngũ.- **Internal Medical Training Blueprints:** Khung chương trình và bộ bài kiểm tra trắc nghiệm kết hợp thực hành lâm sàng bắt buộc, phục vụ cho việc chuyển giao tri thức, đào tạo cấp tốc cho Bác sĩ trẻ và Phụ tá mới vào sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eaf6dc98-e006-4f46-8070-228dbd6cc77a','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 6: POST-TREATMENT CARE OS - HỆ THỐNG CHĂM SÓC HẬU LÂM SÀNG VÀ KÍCH HOẠT VÒNG ĐỜI TÀI SẢN KHÁCH HÀNG','module-6-post-treatment-care-os-he-thong-cham-soc-hau-lam-sang-va-kich-hoat-vong',46,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('592df95d-7960-48b6-8d8f-d9ba6caaec2f','26-clinic-os','eaf6dc98-e006-4f46-8070-228dbd6cc77a',4,'Tư Duy Cốt Lõi: Sưởi Ấm Mối Quan Hệ Sau Điều Trị, Triệt Tiêu Sự Cô Đơn Của Bệnh Nhân','tu-duy-cot-loi-suoi-am-moi-quan-he-sau-ieu-tri-triet-tieu-su-co-on-cua-benh-nhan',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4ba4fcb-03aa-4a61-a525-53780f86cd35','592df95d-7960-48b6-8d8f-d9ba6caaec2f',143,'text','Một lỗi vận hành kinh điển khiến nha khoa truyền thống bị mất dấu bệnh nhân sau ca điều trị lớn là tư duy **"Bán đứt đoạn"** - tức là ngay khi bệnh nhân bước xuống khỏi ghế nha, thanh toán xong hóa đơn và rời khỏi cửa, mối liên kết giữa phòng khám và họ cũng lập tức chấm dứt. Giai đoạn sau khi điều trị tại nhà (đặc biệt là 24 giờ đầu sau cấy Implant hoặc 3 ngày đầu sau siết răng chỉnh nha) chính là lúc bệnh nhân rơi vào trạng thái tổn thương sinh học và nhạy cảm tâm lý cao nhất. Họ phải đối mặt với những cơn đau buốt âm ỉ, nỗi sợ biến chứng chảy máu và sự hoang mang không biết mình có đang hồi phục đúng cách hay không. Nếu phòng khám im lặng, bệnh nhân sẽ cảm thấy bị bỏ rơi và lòng tin bắt đầu rạn nứt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9a6ec3fb-5ab3-4b84-ba7e-c5649a98068c','592df95d-7960-48b6-8d8f-d9ba6caaec2f',144,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập một nguyên lý tối cao: **Việc hoàn tất thủ thuật tại ghế nha không phải là điểm kết thúc của một giao dịch, mà là điểm kích hoạt cho một mối quan hệ lâu dài.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53736c94-26bb-4f3c-815d-4d4b80d9f852','592df95d-7960-48b6-8d8f-d9ba6caaec2f',145,'text','Phân hệ **Post-Treatment Care OS** đóng vai trò là chiếc cầu nối kỹ thuật số, liên kết chặt chẽ ba phân hệ: *Clinic OS (Vận hành lâm sàng)* \\rightarrow *Patient OS (Nuôi dưỡng dài hạn)* \\rightarrow *Review & Referral OS (Thu hoạch tài sản niềm tin)*. Hệ thống này ra đời để số hóa sự thấu cảm của **Bác sĩ** cùng đội ngũ, bảo đảm bao bọc bệnh nhân 24/7 ngoài thực địa, phát hiện sớm các rủi ro y khoa từ xa và biến sự hài lòng sau điều trị thành động cơ tăng trưởng tự nhiên cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0f7456b3-8aca-4a93-a7d8-ad6a999669da','26-clinic-os','eaf6dc98-e006-4f46-8070-228dbd6cc77a',4,'Sáu Mục Tiêu Chiến Lược Định Lượng Đầu Ra','sau-muc-tieu-chien-luoc-inh-luong-au-ra',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1402856-0dfe-4913-adf1-2999d155498f','0f7456b3-8aca-4a93-a7d8-ad6a999669da',146,'text','Hệ thống hậu chăm sóc được lập trình vận hành hằng ngày để giải quyết trọn vẹn 6 bài toán mục tiêu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2eb7eedb-f0d6-472e-840b-987124324658','0f7456b3-8aca-4a93-a7d8-ad6a999669da',147,'text','- **Triệt tiêu sự lo lắng hậu phẫu:** Giải tỏa tâm lý hoang mang, sợ hãi biến chứng của bệnh nhân bằng tri thức dặn dò khoa học, tạo lập cảm giác an toàn như luôn có Bác sĩ đồng hành bên cạnh.- **Khuếch đại chỉ số thấu cảm (Wow CX):** Gia tăng trải nghiệm được quan tâm cá nhân hóa, khiến bệnh nhân cảm nhận phòng khám vận hành bằng sự tử tế y đức chứ không phải vì lợi nhuận thương mại.- **Đánh chặn biến chứng sớm (Risk Mitigation):** Chủ động theo dõi sát sao các phản ứng sinh học của cơ thể (Sưng, đau, chảy máu) để kịp thời đưa ra chỉ dẫn y khoa hoặc điều hướng quay lại phòng khám xử lý cấp tốc.- **Tối ưu hóa tỷ lệ quay lại tái khám (Recall Conversion):** Khóa chặt lịch hẹn kiểm tra cắt chỉ, kiểm tra tốc độ tích hợp xương trụ Implant hoặc lịch siết dây cung định kỳ đúng chu kỳ lâm sàng.- **Tự động hóa dây chuyền thu hoạch Review:** Sàng lọc và kích hoạt lời mời để lại đánh giá 5 sao viết dài kèm hình ảnh thực tế trên Google Maps đối với những bệnh nhân có điểm số hạnh phúc cao.- **Khơi thông dòng thác khách giới thiệu (Referral Network):** Cung cấp đặc quyền tri ân hội viên để bệnh nhân cũ tự nguyện biến thành một đại sứ thương hiệu, chủ động giới thiệu người thân, bạn bè đến phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2d3b3d64-accb-42c1-8be2-35be1edb56f8','26-clinic-os','eaf6dc98-e006-4f46-8070-228dbd6cc77a',4,'Quy Trình Hậu Chăm Sóc 7 Bước Tiêu Chuẩn','quy-trinh-hau-cham-soc-7-buoc-tieu-chuan',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2325bcb4-5b50-463d-9fa1-61535c95b0bf','2d3b3d64-accb-42c1-8be2-35be1edb56f8',148,'text','Mọi hồ sơ bệnh nhân sau khi rời khỏi ghế điều trị của phòng khám bắt buộc phải được hệ thống dẫn dắt dịch chuyển qua đúng đường ống 7 bước khép kín dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ec92a2e-b090-44c3-ad32-e84d4f580a58','2d3b3d64-accb-42c1-8be2-35be1edb56f8',149,'text','***Tại ghế nha: *****Bác sĩ và Phụ tá trực ca bàn giao lời dặn:**Ngay khi hạ ghế, Bác sĩ Vinh hoặc phụ tá trực tiếp dặn dò các lưu ý cốt lõi, trao tận tay túi quà tặng hậu phẫu (Thuốc, bông gạc, bàn chải chuyên dụng) kèm văn bản dặn dò in sẵn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17ff02b1-a7cf-4f90-93a6-dfaf5cf8e2c4','2d3b3d64-accb-42c1-8be2-35be1edb56f8',150,'text','***Tại quầy Lễ tân:***** Khóa mã lịch hẹn tái khám hệ thống:**Lễ tân tiếp nhận Payload bàn giao, tiến hành thanh toán minh bạch và thực hiện khóa cứng khung giờ lịch hẹn tái khám bảo trì tiếp theo trên CRM trước khi khách ra về.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f49c779a-3c4a-4239-ad17-69df0c54de67','2d3b3d64-accb-42c1-8be2-35be1edb56f8',151,'text','***Trong vòng 2 giờ đầu:***** Kích nổ dòng tin nhắn hỏi thăm cấp tốc:**Hệ thống CRM hoặc Chat Agent ca trực chủ động gửi tin nhắn cá nhân hóa qua Zalo hỏi thăm trạng thái hồi phục khi thuốc tê bắt đầu hết tác dụng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6dd9a576-e12a-46c2-a925-bd56af5c2112','2d3b3d64-accb-42c1-8be2-35be1edb56f8',152,'text','***Sau chu kỳ 3 - 7 ngày:***** Đối soát phản hồi sinh học lâm sàng:**Telesales thực hiện cuộc gọi/nhắn tin check-list sức khỏe: Vết thương đã bớt sưng chưa? Ăn nhai có bị vướng cộm khớp cắn không? Khách có tuân thủ uống thuốc đúng giờ không?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62e7b4bd-b04e-4942-89ec-fcdd39165824','2d3b3d64-accb-42c1-8be2-35be1edb56f8',153,'text','***Khi bệnh nhân đạt Peak Wow: *****Thu hoạch tài sản đánh giá thương hiệu:**Nếu dữ liệu đối soát ghi nhận bệnh nhân hoàn toàn hạnh phúc với kết quả, CSKH kích hoạt Script gửi link mã QR điều hướng khách để lại Review 5 sao trên Google Maps.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dcbbce0-a75e-4f1a-9d37-37e5b1d53b41','2d3b3d64-accb-42c1-8be2-35be1edb56f8',154,'text','***Sau khi vết thương ổn định:***** Kích hoạt đòn bẩy giới thiệu người thân:**Gửi thông điệp tri ân, tặng thẻ đặc quyền Voucher chăm sóc răng miệng miễn phí dành riêng cho người thân của bệnh nhân để khơi thông luồng Referral hữu cơ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0a1d2ae-49c7-4e79-8f15-ef81e747323e','2d3b3d64-accb-42c1-8be2-35be1edb56f8',155,'text','***Đóng vòng lặp chuyển đổi:***** Dịch chuyển hồ sơ vào luồng Patient OS:**Chuyển giao trọn vẹn lịch sử bệnh án vào phân hệ chăm sóc dài hạn, định kỳ gửi các nội dung giáo dục thường thức từ kênh theo chu kỳ tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e20b5cc9-a6bd-4e7d-b3c4-174418022cf9','26-clinic-os','eaf6dc98-e006-4f46-8070-228dbd6cc77a',4,'Ma Trận Kịch Bản Tin Nhắn Theo Chặng Thời Gian Vàng (SLA Script Playbook)','ma-tran-kich-ban-tin-nhan-theo-chang-thoi-gian-vang-sla-script-playbook',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7216a98-c01a-4189-bdde-97fc30ac4bfb','e20b5cc9-a6bd-4e7d-b3c4-174418022cf9',156,'text','Tuyệt đối nghiêm cấm việc nhân sự nhắn tin copy-paste vô tri hoặc dùng văn bản tự động của AI bị lỗi hiển thị. Toàn bộ kịch bản giao tiếp qua Zalo cá nhân của khách hàng phải tuân thủ nghiêm ngặt ma trận phân tầng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17509445-262b-4faf-a108-8b0e5a3c9222','e20b5cc9-a6bd-4e7d-b3c4-174418022cf9',157,'image',NULL,'book/26-clinic-os/9572abff-dba2-471f-8f2b-1eb7f2451382-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('796f47f9-b356-45e4-919c-f656eb2ac318','26-clinic-os','eaf6dc98-e006-4f46-8070-228dbd6cc77a',4,'Mỏ Neo Quản Trị: Phương Trình Kích Hoạt Tài Sản Tăng Trưởng (Referral Activation Index)','mo-neo-quan-tri-phuong-trinh-kich-hoat-tai-san-tang-truong-referral-activation-i',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f2463d2-cfc7-4671-89df-50a42c444d5d','796f47f9-b356-45e4-919c-f656eb2ac318',158,'image',NULL,'book/26-clinic-os/27e4fb97-b47e-4f3b-b865-eb1f4ac60bbb-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ae179bb-9b6a-426b-b418-1a8ce00e9ecd','796f47f9-b356-45e4-919c-f656eb2ac318',159,'text','Để kiểm soát nghiêm ngặt năng suất lao động của khối CSKH trực sàn và triệt tiêu tình trạng lãng phí tài nguyên, hệ điều hành *Data OS* áp dụng công thức toán học tính toán chỉ số **Hiệu suất Kích hoạt Tài sản Hậu chăm sóc (Referral Activation Index - RAI)** hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bddd2542-92bb-40c8-948e-ab634fe0c901','796f47f9-b356-45e4-919c-f656eb2ac318',160,'text','RAI = \\left( \\frac{\\text{Số lượng bệnh nhân cũ để lại Review 5 sao hoặc giới thiệu thành công khách mới}}{\\text{Tổng số lượng bệnh nhân đã hoàn tất phác đồ điều trị trong tháng}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d627b15-6d13-4f5c-b4dc-37dea12e7929','796f47f9-b356-45e4-919c-f656eb2ac318',161,'text','- **Ngưỡng mục tiêu tối cao của Thích Làm Răng:** Chỉ số RAI bắt buộc phải đạt mốc **\\ge 35\\%**.- **Ý nghĩa quản trị vĩ mô:** Nếu chỉ số RAI < 20\\%, bộ máy đang gặp lỗi sàn nghiêm trọng ở khâu chăm sóc: Hoặc kịch bản nhắn tin quá hời hợt, hoặc nhân sự quên không xin review, hoặc trải nghiệm lâm sàng tại ghế nha của bác sĩ quá thô bạo làm khách sợ hãi, không bao giờ muốn quay lại hay giới thiệu cho bất kỳ ai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dbbef3b0-18c1-42c4-a52c-6cdb1c9bf66f','796f47f9-b356-45e4-919c-f656eb2ac318',162,'text','**Mantra điều hành tối thượng của Post-Treatment Care OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72e0aebf-f225-4a77-956f-98028d0de143','796f47f9-b356-45e4-919c-f656eb2ac318',163,'text','*"Sự tử tế của một người thầy thuốc không dừng lại khi bệnh nhân bước ra khỏi phòng phẫu thuật. Nó nằm ở cái cách chúng ta kiên trì nhắn tin hỏi thăm, bao bọc và lo lắng cho từng cơn đau của người bệnh khi họ đang ở nhà. Khi bệnh nhân cảm nhận được sự chân thành tầng sâu, họ sẽ tự động biến thành những pháo đài truyền thông mạnh mẽ nhất bảo vệ cho thương hiệu của bạn."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f0d70af7-a3df-4d79-bb10-8801d4368f89','26-clinic-os','3dde6227-353a-42ea-a47d-53c032d653b7',3,'MODULE 7: CASE &amp; REVIEW CAPTURE OS - HỆ THỐNG SỐ HÓA VÀ KHAI THÁC TÀI SẢN NIỀM TIN LÂM SÀNG','module-7-case-amp-review-capture-os-he-thong-so-hoa-va-khai-thac-tai-san-niem-ti',52,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('78218fbe-81e0-4c5e-80a1-d0c3186da89c','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Tư Duy Cốt Lõi: Biến Kết Quả Lâm Sàng Thành Động Cơ Tăng Trưởng Bền Vững','tu-duy-cot-loi-bien-ket-qua-lam-sang-thanh-ong-co-tang-truong-ben-vung',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02432d1e-f7c0-46a2-b889-57f4ae0396a1','78218fbe-81e0-4c5e-80a1-d0c3186da89c',164,'text','Một trong những sự lãng phí tài nguyên khủng khiếp nhất tại các phòng khám nha khoa truyền thống là trạng thái **"Vô hình hóa năng lực chuyên môn"**. Bác sĩ có thể thực thi hàng trăm ca cấy ghép Implant hoàn hảo, chỉnh sửa hàng chục ca lệch lạc cung hàm vô cùng phức tạp, nhưng sau khi bệnh nhân bước xuống ghế nha, toàn bộ những kiệt tác lâm sàng đó đều biến mất vào hư không. Phòng khám làm rất nhiều ca tốt nhưng không tích lũy được tài sản thương hiệu, dẫn đến việc *Marketing OS* liên tục rơi vào trạng thái "đói" chất liệu thực chứng sạch, buộc phải sử dụng các hình ảnh stock mua sẵn vô tri hoặc nói lý thuyết suông, làm giảm sụt nghiêm trọng sức mạnh thuyết phục đầu phễu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56569a77-9dfb-4024-98e1-5fa882f9bce5','78218fbe-81e0-4c5e-80a1-d0c3186da89c',165,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập tư duy: **Mỗi ca điều trị thành công tại phòng khám không chỉ là một nhiệm vụ y khoa đã hoàn tất, mà là một khối tài sản truyền thông tối cao có năng lực sinh lời và tự động sản sinh ra khách hàng mới.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('93a4267c-ed72-440f-83a2-175f5d716b7a','78218fbe-81e0-4c5e-80a1-d0c3186da89c',166,'text','Phân hệ **Case & Review Capture OS** ra đời để đóng vai trò là chiếc cầu nối vàng, chịu trách nhiệm "thu hoạch" và chuyển hóa toàn bộ tri thức, kết quả lâm sàng của **Bác sĩ Nguyễn Phước Vinh** cùng đội ngũ tại Hà Nội thành kho vũ khí sắc bén cho *Marketing OS* và *Sales OS*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('52c89a12-50e2-4aa0-a7c1-7ca825dc2c9a','78218fbe-81e0-4c5e-80a1-d0c3186da89c',167,'text','**Tuyên ngôn tối cao của phân hệ:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('314f1af0-6781-4b7e-81f3-c64c06021ad2','78218fbe-81e0-4c5e-80a1-d0c3186da89c',168,'text','*"Làm 100 ca giỏi mà không đóng gói thành tài sản truyền thông thì thế giới trực tuyến vẫn coi như bạn chưa từng tồn tại. Hãy công nghiệp hóa quy trình thu hoạch niềm tin để biến mỗi bệnh nhân hạnh phúc thành một đại sứ thương hiệu vĩnh cửu."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a4f6a3a6-db1a-447d-8f59-a13f4290a007','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Danh Mục 7 Tài Sản Niềm Tin Tối Cao (The Trust Assets Bundle)','danh-muc-7-tai-san-niem-tin-toi-cao-the-trust-assets-bundle',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e59975e-a20f-41e9-ac59-1d819f9dbf36','a4f6a3a6-db1a-447d-8f59-a13f4290a007',169,'text','Để kho đạn dược truyền thông của nha khoa **Thích Làm Răng** luôn dồi dào và đạt tiêu chuẩn thuyết phục cao nhất, hệ thống quy định 7 loại tài sản bắt buộc khối lâm sàng và khối truyền thông phải thu thập phối hợp hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4b2b4c6-f104-4247-bc13-4dadf8d717db','a4f6a3a6-db1a-447d-8f59-a13f4290a007',170,'image',NULL,'book/26-clinic-os/9a544ff3-26ae-4707-b40b-819666886fd9-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4ee78845-fc06-45fa-ba90-a9d7c85e59de','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Quy Trình Thu Hoạch Tài Sản 7 Bước Tuyến TínhQuy trình thu hoạch tài sản không được diễn ra một cách ngẫu hứng sau khi ca điều trị đã kết thúc. Nó là một đường ống khép kín, chạy song song với tiến trình lâm sàng theo đúng 7 mốc chặn bắt buộc sau:','quy-trinh-thu-hoach-tai-san-7-buoc-tuyen-tinhquy-trinh-thu-hoach-tai-san-khong-u',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('beebfcb3-f1b6-467a-b6a5-67d5b967e62d','4ee78845-fc06-45fa-ba90-a9d7c85e59de',171,'text','***Chặng 1: Sàng lọc - *****Xác định Case mục tiêu đạt chuẩn truyền thông:**Bác sĩ chủ trì phối hợp với Điều phối viên sàn rà soát lịch hẹn tuần, lọc ra các ca lâm sàng có tính đại diện cao (Hô móm nặng, mất răng lâu năm) có giá trị giáo dục thị trường lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8424e201-47bd-40de-8224-b66a9055343f','4ee78845-fc06-45fa-ba90-a9d7c85e59de',172,'text','***Chặng 2: Pháp lý số -***** Ký biên bản đồng thuận sử dụng hình ảnh (Consent Form):**TCO hoặc CSKH ngồi phòng VIP trao đổi thẳng thắn, xin phép bệnh nhân được sử dụng hình ảnh che mắt/video phục vụ mục đích y khoa và truyền thông tử tế. Trao đặc quyền tri ân đặc biệt cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1bf263a5-fcb0-477f-9d62-bbafa5556199','4ee78845-fc06-45fa-ba90-a9d7c85e59de',173,'text','***Chặng 3: Dữ liệu gốc -***** Chụp bộ ảnh và Video Trước điều trị (Before):**Trợ thủ đưa bệnh nhân vào phòng Studio/Phòng máy, thực hiện chụp bộ ảnh răng 8 góc tiêu chuẩn và quay video ngắn ghi nhận diện mạo, khuyết điểm nụ cười ban đầu của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8077d979-9bc4-4ba5-96ba-169043f8e1a1','4ee78845-fc06-45fa-ba90-a9d7c85e59de',174,'text','***Chặng 4: Thực địa -***** Ghi nhận lát cắt diễn biến lâm sàng (In-Progress):**Trong quá trình Bác sĩ thực hiện thủ thuật tại ghế nha, Phụ tá hoặc kỹ thuật viên hình ảnh bấm máy bắt trọn góc quay công nghệ cao, thao tác chuẩn y đức khéo léo của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1511b070-1c0c-4495-b023-74ddb9f91341','4ee78845-fc06-45fa-ba90-a9d7c85e59de',175,'text','***Chặng 5: Đỉnh cao Wow -***** Chụp bộ ảnh hoàn tất phác đồ (After):**Tại buổi hẹn nghiệm thu tháo niềng hoặc lắp răng sứ/Implant cuối cùng, thực hiện chụp lại bộ ảnh răng đạt độ khít sát thẩm mỹ tối cao trong trạng thái bệnh nhân hạnh phúc nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab28674e-1f57-4de6-a9eb-5c0869648ac3','4ee78845-fc06-45fa-ba90-a9d7c85e59de',176,'text','***Chặng 6: Thu hoạch kho -***** Phỏng vấn sâu cảm nhận Testimonial:**Bộ phận CSKH trực sàn kích hoạt kịch bản đặt câu hỏi bóc tách hành trình: *"Trước đây mình sợ gì? Giờ làm xong mình thấy ăn nhai ra sao? Bác sĩ làm có nhẹ nhàng không?"* và hướng dẫn quét QR Google Maps.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad332b2d-4568-4082-a5ad-3c81eade70f9','4ee78845-fc06-45fa-ba90-a9d7c85e59de',177,'text','***Chặng 7: Đóng lặp -***** Đóng gói Payload và Bàn giao sang Marketing OS:**Sales Manager thực hiện kiểm toán, gom toàn bộ file ảnh gốc, video thô, kịch bản chữ cảm nhận nạp vào thư viện tài sản `Trust Assets Library`, chuyển giao lệnh cho khối Media sản xuất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ba0faaa2-0d8d-44fe-b932-37a6a093b127','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Bảng Checklist Hiệu Suất Đầu Ra (The Case &amp; Review Audit Checklist)','bang-checklist-hieu-suat-au-ra-the-case-amp-review-audit-checklist',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f6192f3-591c-483c-9364-749a82e05ae5','ba0faaa2-0d8d-44fe-b932-37a6a093b127',178,'text','Để đảm bảo không một ca lâm sàng xuất sắc nào bị bỏ phí, Tư vấn trưởng thực hiện đối soát chất lượng đóng gói tài sản hằng tuần theo bảng tiêu chuẩn định lượng cứng dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de63925b-713f-49cd-b926-60539578fde9','ba0faaa2-0d8d-44fe-b932-37a6a093b127',179,'image',NULL,'book/26-clinic-os/3ca77d80-e39e-43ee-b757-5906407051b2-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dfdf0492-ad41-4f37-a8db-1aca2eb18e35','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Mỏ Neo Toán Học: Chỉ Số Sản Sinh Tài Sản Số (Asset Generation Index)','mo-neo-toan-hoc-chi-so-san-sinh-tai-san-so-asset-generation-index',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8601a441-6f82-41b4-ae30-fd459f04f2b5','dfdf0492-ad41-4f37-a8db-1aca2eb18e35',180,'image',NULL,'book/26-clinic-os/947bd404-b8cc-49e3-9ffa-492596d2d1c3-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c2181f4-bf51-4b02-abd0-204e07843048','dfdf0492-ad41-4f37-a8db-1aca2eb18e35',181,'text','Hệ điều hành kiểm soát năng lực phối hợp giữa khối Lâm sàng và khối Truyền thông trong việc tích lũy tài sản thương hiệu thông qua công thức toán học đo lường **Chỉ số Sản sinh Tài sản Số (Asset Generation Index - AGI)** hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17bb8d88-409a-4ed8-95b4-fdeabb009661','dfdf0492-ad41-4f37-a8db-1aca2eb18e35',182,'text','AGI = \\left( \\frac{\\text{Số lượng ca lâm sàng được đóng gói tài sản số đạt chuẩn 8/8 mục Checklist}}{\\text{Tổng số lượng ca can thiệp dịch vụ mũi nhọn hoàn tất thực tế trong chu kỳ}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f08229fb-9159-47eb-8833-71e1369f5db9','dfdf0492-ad41-4f37-a8db-1aca2eb18e35',183,'text','- **Ngưỡng mục tiêu vận hành tối thiểu:** Chỉ số AGI của nha khoa bắt buộc phải được kiểm soát nằm ở mốc **\\ge 40\\%**.- **Ý nghĩa quản trị vĩ mô:** Nếu chỉ số AGI < 20\\%, chứng tỏ phòng khám đang mắc lỗi nghẽn mạch phối hợp nội bộ trầm trọng. Bác sĩ chỉ lo chữa bệnh, phụ tá lười chụp ảnh, truyền thông bỏ bê thực địa. Ban giám đốc nhìn vào chỉ số này để điều chỉnh lại cơ chế thưởng phạt dòng tiền, ép bộ máy phải tự giác đi "săn tìm tài sản niềm tin" hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f524e935-4daa-42be-b358-ca7138bdd4e0','26-clinic-os','f0d70af7-a3df-4d79-bb10-8801d4368f89',4,'Bộ Đầu Ra Tài Liệu Tiêu Chuẩn Đóng Gói (Deliverables Bundle)','bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',58,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c21855a-dff3-4186-80fb-76ba325a94b3','f524e935-4daa-42be-b358-ca7138bdd4e0',184,'text','Để phân hệ Case & Review Capture OS được vận hành trơn tru như một phần mềm lập trình sẵn, ban điều hành bắt buộc phải hoàn thiện và ban hành bộ 5 tài sản mã nguồn sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e9ca428c-e4c0-4087-8c25-d22503316353','f524e935-4daa-42be-b358-ca7138bdd4e0',185,'text','- **Legal Patient Image Consent Form:** Văn bản pháp lý thỏa thuận quyền sử dụng hình ảnh truyền thông tử tế, được phê duyệt bởi ban cố vấn luật y tế.- **Standardized DSLR Dental Photography SLA:** Bộ tài liệu atlas quy chuẩn kỹ thuật chụp ảnh răng đầu ghế nha (Quy định thông số khẩu độ, tốc độ màn trập, cách đặt gương và banh miệng chuẩn y khoa).- **Patient Interview Script Playbook:** Bộ câu hỏi phỏng vấn tâm lý sâu tại phòng VIP giúp khơi gợi cảm xúc, khiến bệnh nhân tự kể lại hành trình vượt qua nỗi sợ đau sinh học một cách tự nhiên.- **Google Maps Review Optimization Script:** Quy trình và lời thoại hướng dẫn của lễ tân giúp tối ưu hóa từ khóa SEO địa phương khi xin đánh giá 5 sao của khách hàng hằng ngày.- **Centralized Cloud Trust-Asset Library Spec:** Kiến trúc phân loại và đặt tên thư mục thông minh trên Drive/CRM giúp đồng bộ hóa, trích xuất tài nguyên thần tốc cho Media Buyer chạy quảng cáo dưới 30 giây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6404827a-fc5b-4a65-92d7-d1343a8185d6','f524e935-4daa-42be-b358-ca7138bdd4e0',186,'text','**Mantra điều hành tối thượng của Case & Review Capture OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46a0bdee-192f-43e1-95b5-860eb07dc4c0','f524e935-4daa-42be-b358-ca7138bdd4e0',187,'text','*"Đừng bắt Marketing phải bóp óc suy nghĩ ra những câu từ giật gân, sáo rỗng để thu hút khách hàng. Hãy trao cho họ những bằng chứng khoa học thép, những nụ cười lột xác rạng rỡ và những giọt nước mắt hạnh phúc của bệnh nhân thật. Sự thật y khoa chính là thứ ngôn ngữ có sức mạnh chuyển đổi tối thượng và tử tế nhất."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb7bf2b3-5b72-4110-84dc-03cff4c78c9f','26-clinic-os',NULL,2,'26.5 KPI gợi ý cho Clinic OS','265-kpi-goi-y-cho-clinic-os',59,'[]');
