INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a8ead7fd-5ea1-47c0-a0eb-557ed25019d5','26-clinic-os',NULL,2,'26.6 Clinic OS Dashboard','266-clinic-os-dashboard',60,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8fafe7f-15f0-4651-ab2d-ff818819963c','26-clinic-os','a8ead7fd-5ea1-47c0-a0eb-557ed25019d5',3,'Trung Tâm Điều Hành Và Kiểm Soát Sức Khỏe Vận Hành Thời Gian Thực','trung-tam-ieu-hanh-va-kiem-soat-suc-khoe-van-hanh-thoi-gian-thuc',61,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11678ffe-d2b2-43c7-8b28-c3cc8218dbb5','f8fafe7f-15f0-4651-ab2d-ff818819963c',189,'text','Để một nhà quản trị hay Bác sĩ sáng lập làm chủ hoàn toàn dữ liệu thực địa mà không cần phải có mặt 24/7 tại phòng khám, **Clinic OS** cần được số hóa thành một bảng điều khiển trung tâm (Master Dashboard). Bảng điều khiển này trích xuất trực tiếp dữ liệu thời gian thực từ phần mềm CRM/ERP, bóc tách các chỉ số định tính mơ hồ thành các con số khoa học biết nói.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4db64902-612a-410b-b26b-4a812d3bb7c2','f8fafe7f-15f0-4651-ab2d-ff818819963c',190,'text','Dashboard của nha khoa không chỉ hiển thị doanh thu đơn thuần, mà tập trung kiểm soát **tốc độ dòng chảy dữ liệu, năng suất khai thác tài sản cứng và mức độ an toàn sinh học lâm sàng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('be2eb1fe-e002-4d21-8094-0922cc903574','26-clinic-os','a8ead7fd-5ea1-47c0-a0eb-557ed25019d5',3,'Cấu Trúc 4 Phân Hệ Đối Soát Của Clinic OS Dashboard','cau-truc-4-phan-he-oi-soat-cua-clinic-os-dashboard',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4a98b8d-3dc2-490d-9898-378e8538e187','be2eb1fe-e002-4d21-8094-0922cc903574',191,'text','Bảng điều khiển tối cao được chia nhỏ thành 4 màn hình kiểm soát độc lập, giúp người điều hành nhận diện điểm nghẽn (Bottlenecks) trên sàn vật lý chỉ trong vòng 30 giây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('398bef6a-a923-445a-9568-ba49821e1c8e','be2eb1fe-e002-4d21-8094-0922cc903574',192,'text','**1.1 Panel 1: Hiệu Suất Trực Sàn Và Khai Thác Ghế Nha (Asset Capacity)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b088186-681c-4f52-a35f-9d63fc6e6a2f','be2eb1fe-e002-4d21-8094-0922cc903574',193,'image',NULL,'book/26-clinic-os/fb3c8a69-dbd2-4a65-ba84-7a46dc20fdf0-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9cfe229e-cb47-49f4-86d5-3b503bc51389','be2eb1fe-e002-4d21-8094-0922cc903574',194,'text','Màn hình này đo lường mức độ tối ưu hóa công suất của tài sản có giá trị lớn nhất phòng khám - Chiếc ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a1a3bc3-7df1-416e-9e69-b8f1d9d8dc6f','be2eb1fe-e002-4d21-8094-0922cc903574',195,'text','- **Chỉ số CUI (Chair-Time Utilization Index):** Tỷ lệ phần trăm thời gian ghế nha hoạt động sinh lời thực tế trên tổng công suất mở cửa tiêu chuẩn.- CUI = \\left( \\frac{\\text{Tổng số giờ ghế nha điều trị thực tế}}{\\text{Tổng số giờ mở cửa phòng khám} \\times \\text{Tổng số lượng ghế nha}} \\right) \\times 100\\%
- **Chỉ số CIL (Chair Idle Leakage):** Tổng số phút ghế nha bị bỏ trống lãng phí giữa hai ca điều trị liên tiếp do lỗi setup phòng chậm của phụ tá hoặc lỗi điều phối của lễ tân.- **Tỷ lệ No-Show thực sàn (%):** Tỷ lệ bệnh nhân bùng lịch hẹn hoặc hủy lịch giờ chót mà không được bộ phận Telesales đánh chặn kịp thời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8b573b00-812d-4573-ba13-9fa75f507760','be2eb1fe-e002-4d21-8094-0922cc903574',196,'text','**1.2 Panel 2: Tốc Độ Và Ma Sát Tiền Sàn (Front Desk Operation)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cec6c190-71f2-4bc3-a103-2bb453ffa948','be2eb1fe-e002-4d21-8094-0922cc903574',197,'text','Kiểm soát năng lực đón tiếp, đo lường ma sát điểm chạm đầu tiên khi bệnh nhân bước qua bậu cửa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad79f21b-f87f-4bdd-b913-0bb9bf71bcc2','be2eb1fe-e002-4d21-8094-0922cc903574',198,'text','- **SLA Attainment Rate (%):** Tỷ lệ quầy Lễ tân xử lý check-in hồ sơ và đưa bệnh nhân lên ghế nha/phòng máy đúng hạn định mức quy định.- **Chỉ số IFI (Intake Friction Index):** Chỉ số ma sát tiếp nhận tiền sàn.- IFI = \\frac{\\text{Tổng số phút bệnh nhân phải ngồi chờ thực tế từ lúc Check-in đến khi lên ghế nha}}{\\text{Thời gian hẹn tiêu chuẩn định mức quy định (5 phút)}}
- **Dòng chảy trạng thái thực (Real-time Pipeline Status):** Số lượng hồ sơ đang nằm ở các trạng thái: `Booked` (Đã hẹn) \\rightarrow `Arrived` (Đã đến sảnh) \\rightarrow `Treatment Started` (Đang trên ghế nha) \\rightarrow `Checked Out` (Đã hoàn tất thanh toán).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('195a1c81-9c5e-4fe4-9005-166843e6fc7a','be2eb1fe-e002-4d21-8094-0922cc903574',199,'text','**1.3 Panel 3: Chất Lượng Lâm Sàng Và Sự Thấu Cảm (Clinical Quality & CX)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eebda832-71f4-468c-981b-95e3aee96887','be2eb1fe-e002-4d21-8094-0922cc903574',200,'text','Hàng rào kỹ thuật bảo vệ y đức, đo lường mức độ an toàn y khoa và chỉ số hạnh phúc của người bệnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb203e9b-e938-4282-9886-7b6bfc292fd6','be2eb1fe-e002-4d21-8094-0922cc903574',201,'text','**Chỉ số CQCR (Clinical Quality Compliance Rate):** Tỷ lệ tuân thủ chất lượng lâm sàng, chấm điểm dựa trên việc hồ sơ có đủ phim chụp 3D, bộ ảnh răng DSLR nghiệm thu và phim đối soát cận chóp đầu ra hay không.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85b019ff-b569-4d86-a025-602356fd0563','be2eb1fe-e002-4d21-8094-0922cc903574',202,'text','CQCR (\\%) = \\left( \\frac{N_{\\text{đạt chuẩn}}}{N_{\\text{kiểm toán}}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c89b285-7dab-485e-b6a5-b4848082aca6','be2eb1fe-e002-4d21-8094-0922cc903574',203,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2115104-6de8-4b03-83dc-6776437a151b','be2eb1fe-e002-4d21-8094-0922cc903574',204,'text','- N_{\\text{đạt chuẩn}}: Số lượng hồ sơ bệnh nhân hoàn tất thủ thuật/phẫu thuật trong kỳ có điểm số kiểm toán cấu phần đạt tuyệt đối (S_{\\text{hồ sơ}} = 100\\%).- N_{\\text{kiểm toán}}: Tổng số lượng hồ sơ bệnh nhân đã can thiệp lâm sàng được trích xuất để kiểm tra ngẫu nhiên hoặc toàn bộ trong kỳ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8aea3c23-66ac-4b71-b223-4b9b94fb9feb','be2eb1fe-e002-4d21-8094-0922cc903574',205,'text','**Chỉ số PSS (Patient Sentiment Score):** Chỉ số hạnh phúc của bệnh nhân trích xuất từ hệ thống khảo sát bí mật tự động qua Zalo OA ngay sau khi ra về.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db0a4d7d-8b36-4e02-a18c-d7a978b73528','be2eb1fe-e002-4d21-8094-0922cc903574',206,'text','PSS (\\%) = \\left( \\frac{N_{\\text{Wow}}}{N_{\\text{Total Feedback}}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e6dd693d-bba7-4491-95f3-6bcb5a89aac1','be2eb1fe-e002-4d21-8094-0922cc903574',207,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06fcbb0a-320d-4ff1-8c73-510355c60a71','be2eb1fe-e002-4d21-8094-0922cc903574',208,'text','- N_{\\text{Wow}}: Số lượng phiếu khảo sát trích xuất từ hệ thống đạt điểm số tối đa tuyệt đối (5/5 sao) cho câu hỏi "Đánh giá trải nghiệm tổng thể ngày hôm nay".- N_{\\text{Total Feedback}}: Tổng số lượng phiếu khảo sát mà phòng khám thu về thực tế từ bệnh nhân trong chu kỳ kiểm toán (tuần/tháng).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('598622a9-1f82-413d-a716-bd4ed2d105a2','be2eb1fe-e002-4d21-8094-0922cc903574',209,'text','**Tỷ lệ tai biến & khiếu nại CCCR (%) (CLINICAL COMPLICATIONS & COMPLAINTS RATE ):** Số ca gặp sự cố đào thải trụ, hở đường hoàn tất răng sứ hoặc có phản hồi tiêu cực cần kích hoạt phòng VIP xử lý khủng hoảng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4ec857b-72d7-4f1a-b3e7-9b43111d105a','be2eb1fe-e002-4d21-8094-0922cc903574',210,'text','CCCR (\\%) = \\left( \\frac{N_{\\text{tai biến}} + N_{\\text{khiếu nại}}}{N_{\\text{tổng ca phát sinh}}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e066316a-c016-4727-9411-8fd19451b08c','be2eb1fe-e002-4d21-8094-0922cc903574',211,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7393fd9-f7b4-4bc7-bb17-078f01fed220','be2eb1fe-e002-4d21-8094-0922cc903574',212,'text','- N_{\\text{tai biến}}: Số lượng bệnh nhân gặp sự cố lâm sàng thực tế được Bác sĩ xác nhận (Ví dụ: Đào thải trụ Implant, viêm nướu vùng quanh răng điều trị, lệch khớp cắn nặng).- N_{\\text{khiếu nại}}: Số lượng bệnh nhân phản hồi tiêu cực, thể hiện sự giận dữ qua các kênh Hotline, Chat, Google Maps hoặc trực tiếp tại sảnh chờ mà không được giải quyết êm đẹp trong vòng 12 giờ.- N_{\\text{tổng ca phát sinh}}: Tổng số lượt thủ thuật/phẫu thuật lâm sàng hoàn tất thực tế của phòng khám trong chu kỳ kiểm toán.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9aee81cb-b50c-485a-866d-89db85d6d7ac','be2eb1fe-e002-4d21-8094-0922cc903574',213,'text','**1.4 Panel 4: Nhà Máy Sản Xuất Tài Sản Niềm Tin (Asset Acquisition Pipeline)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10ace50e-e938-4c8b-b130-a51e8c3b61cd','be2eb1fe-e002-4d21-8094-0922cc903574',214,'text','Đo lường năng lực thu hoạch nguyên liệu sạch đầu phễu của khối lâm sàng bàn giao cho team Marketing.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e869fdfd-f727-40bf-8e82-67316d0acd9f','be2eb1fe-e002-4d21-8094-0922cc903574',215,'text','- **Chỉ số AGI (Asset Generation Index):** Tỷ lệ số ca can thiệp can thiệp sâu (Implant, Chỉnh nha) được đóng gói thành công bộ tư liệu Before/After chuẩn SLA ảnh Studio và video ngắn công nghệ cao.- **Sản lượng Review Google Maps mới:** Số lượng đánh giá 5 sao viết dài có đính kèm ảnh thực tế thu hoạch được trong tuần.- **Chỉ số RAI (Referral Activation Index):** Tỷ lệ bệnh nhân cũ kích hoạt thành công mã giới thiệu, đưa người thân, bạn bè đến cơ sở Hà Nội điều trị lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('889d90c0-51c5-4591-be61-52d39d81f72d','26-clinic-os','a8ead7fd-5ea1-47c0-a0eb-557ed25019d5',3,'Trình Mô Phỏng Sức Khỏe Vận Hành Và Thất Thoát Tài Chính (Clinic OS Simulator)','trinh-mo-phong-suc-khoe-van-hanh-va-that-thoat-tai-chinh-clinic-os-simulator',63,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86cc9eda-0e04-4be6-9cb5-67094d75b703','889d90c0-51c5-4591-be61-52d39d81f72d',216,'text','Để anh trực quan hóa việc các chỉ số KPI vận hành thực địa ảnh hưởng như thế nào đến doanh thu và công suất của phòng khám, anh có thể sử dụng trình mô phỏng thuật toán dưới đây. Hãy thử điều chỉnh các biến số ma sát (Tỷ lệ No-show, Thời gian trống ghế) để nhìn thấy số tiền bị rò rỉ thực tế hằng tháng của nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ab3f277-b6ab-48c0-b607-8fd68322f715','889d90c0-51c5-4591-be61-52d39d81f72d',217,'text','**Mantra tối thượng của Clinic OS Dashboard:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4811d261-638d-4c28-bd0d-9d2cb6487922','889d90c0-51c5-4591-be61-52d39d81f72d',218,'text','*"Cái gì đo lường được thì cái đó mới quản trị và tối ưu hóa được. Đừng điều hành một phòng khám nha khoa bằng cảm giác hay những lời báo cáo màu hồng của nhân sự. Hãy để dữ liệu số hóa thời gian thực phơi bày mọi sự thật vận hành, giúp anh đưa ra những quyết định sửa sai y khoa và tài chính chính xác tuyệt đối."*',NULL,NULL,NULL,NULL,NULL);
