INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddf7c103-0151-4e7f-b836-b7bb39f1fc20','e1ca6720-72a3-4300-aeac-028544e7f686',226,'image',NULL,'book/26-clinic-os/0f521180-864a-47e1-ad49-1b8673e847c5-img27.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71d4dcac-5550-4145-adc5-5612fc4d95e3','26-clinic-os',NULL,2,'26.12 Kết Luận','2612-ket-luan',78,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe6dbbac-0cdd-4061-9dcc-c92ee86826e6','71d4dcac-5550-4145-adc5-5612fc4d95e3',227,'text','Trong kiến trúc tổng thể của hệ điều hành quản trị nha khoa, **Clinic OS chính là trái tim vận hành thực địa**. Nếu phân hệ Marketing OS chịu trách nhiệm thắp sáng thương hiệu và Sales OS chịu trách nhiệm kéo khách hàng về đường ống trực tuyến, thì Clinic OS là nơi duy nhất giữ bệnh nhân ở lại bằng năng lực lâm sàng tầng sâu và sự tử tế trong trải nghiệm vật lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f266881-4364-4181-b33d-c75ff5e850fe','71d4dcac-5550-4145-adc5-5612fc4d95e3',228,'text','Một phòng khám đổ hàng trăm triệu đồng vào quảng cáo để có độ phủ truyền thông mạnh nhưng lại sở hữu một hệ thống Clinic OS yếu kém, rời rạc sẽ ngay lập tức rơi vào cái bẫy sụt lún vận hành nguy hiểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8907823-2dbb-4b18-8e77-15cd8a98c01d','26-clinic-os','71d4dcac-5550-4145-adc5-5612fc4d95e3',3,'Các Điểm Nghẽn Tử Huyệt Khi Buông Lỏng Clinic OS','cac-iem-nghen-tu-huyet-khi-buong-long-clinic-os',79,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb9b87ad-125d-4200-a72d-69de046593e6','f8907823-2dbb-4b18-8e77-15cd8a98c01d',229,'text','Khi rào cản quy trình sàn vật lý bị đứt gãy, phòng khám sẽ phải đối mặt với chuỗi hệ lụy rò rỉ dòng tiền mặt và uy tín y khoa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa179418-5b17-40c2-8d22-bee7c201f874','f8907823-2dbb-4b18-8e77-15cd8a98c01d',230,'text','- **Có Lead nhưng không chuyển đổi tốt:** Khách hàng đến sảnh chờ nhưng phải đợi vô định quá ngưỡng SLA 5 phút, Lễ tân lóng ngóng không khớp dữ liệu tâm lý khiến khách tụt cảm xúc, phát sinh phòng thủ và từ chối phác đồ.- **Có bệnh nhân nhưng trải nghiệm kém:** Khâu thăm khám nặng mùi chèo kéo thương mại hoặc Bác sĩ lạm dụng thuật ngữ y khoa hàn lâm khiến bệnh nhân choáng ngợp, sợ hãi đau buốt sinh học và bỏ về.- **Có điều trị nhưng không tạo Review:** Ca điều trị Implant hay Chỉnh nha thành công mỹ mãn nhưng nhân sự trực sàn thờ ơ, quên không hướng dẫn khách quét mã QR để lại đánh giá 5 sao trên Google Maps.- **Có Case tốt nhưng không ghi nhận:** Bác sĩ thực thi những kiệt tác lột xác nụ cười đỉnh cao nhưng Phụ tá lười chụp ảnh DSLR, dẫn đến việc Marketing OS luôn rơi vào trạng thái "đói" chất liệu thực chứng sạch.- **Có khách hàng hài lòng nhưng không tạo Referral:** Bệnh nhân rất quý phòng khám nhưng hệ thống không kích hoạt đòn bẩy giới thiệu, làm lãng phí tệp khách hàng hữu cơ có chi phí CAC bằng 0.- **Có doanh thu nhưng khó mở rộng ổn định:** Vận hành hoàn toàn phụ thuộc vào tâm trạng hằng ngày của con người và năng suất của một vài "ngôi sao" lâm sàng, khiến phòng khám không thể tự động hóa hay nhân bản quy mô.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c97e03ac-5047-4499-96c2-427ce879df69','26-clinic-os','71d4dcac-5550-4145-adc5-5612fc4d95e3',3,'Bánh Đà Vòng Lặp Tăng Trưởng Vĩnh Cửu Khi Clinic OS Mạnh Mẽ','banh-a-vong-lap-tang-truong-vinh-cuu-khi-clinic-os-manh-me',80,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4025a240-afb1-4a16-9d5a-2e3321dc1209','c97e03ac-5047-4499-96c2-427ce879df69',231,'text','Ngược lại, khi các module từ Reception OS, Diagnosis OS đến Chairside Operation OS được ráp nối khít sát và vận hành với kỷ luật thép, mỗi bệnh nhân bước vào nha khoa **Thích Làm Răng** sẽ tự động kích nổ một chuỗi phản ứng tăng trưởng lũy tiến tự nhiên cho hệ thống:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('87c4a6a5-e146-4a5c-9794-2efdf64f4cd7','26-clinic-os','71d4dcac-5550-4145-adc5-5612fc4d95e3',3,'Giá Trị Nhân Văn Của Clinic OS','gia-tri-nhan-van-cua-clinic-os',81,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4136888f-dfc3-481b-a98f-461698a66b40','87c4a6a5-e146-4a5c-9794-2efdf64f4cd7',232,'text','**Mantra tối thượng của toàn phân hệ:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e675b04c-0f32-469d-81f8-fcbd841afa1f','87c4a6a5-e146-4a5c-9794-2efdf64f4cd7',233,'text','*"Clinic OS không đơn thuần là một hệ thống quản lý thủ thuật điều trị hay điều phối ghế nha. Clinic OS chính là hệ thống chuyển hóa: Biến năng lực chuyên môn lâm sàng thành niềm tin sắt đá, biến nỗi sợ hãi sinh học thành trải nghiệm an tâm, biến kết quả ca điều trị thành tài sản thương hiệu trường tồn và biến y đức tử tế thành động cơ tăng trưởng vĩ cửu cho phòng khám."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56b32587-bfcf-496f-bf18-4cec6ea4462d','87c4a6a5-e146-4a5c-9794-2efdf64f4cd7',234,'text','Đến đây, toàn bộ kiến trúc hạ tầng vận hành sàn của **Clinic OS **đã được thiết lập hoàn tất, sẵn sàng để đưa vào cấu hình cứng trên hệ thống quản trị, chắp cánh cho sứ mệnh chăm sóc nụ cười con người của anh đi xa và bền vững nhất.',NULL,NULL,NULL,NULL,NULL);
